import {
	ChangeDetectionStrategy,
	Component,
	ElementRef,
	EventEmitter,
	Input,
	OnInit,
	Output,
	ViewChild,
} from "@angular/core";
import { CommonUtil, HtmlUtil, StringUtil } from "lime";
import {
	DisplayNamePipe,
	IPage,
	IPageData,
	LanguageService,
	PageColor,
	PageUtil,
	UIUtil,
} from "lime/core";
import { CatalogService } from "../catalog-core";

export interface ICatalogItem {
	title?: string;
	description?: string;
	widgetId?: string;
	data?: IPageData;
	tags?: string;
	displayIcon?: string;
	featuredClass?: string;
	standardWidgetId?: string;
	id?: string;
	category?: number;
}

export interface ICatalogAddInfo {
	item: ICatalogItem;
	isDuplicate?: boolean;
}

@Component({
	selector: "lm-catalog-item-component",
	templateUrl: "./catalog-item.html",
	styleUrls: ["./catalog-item.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CatalogItemComponent implements OnInit {
	@ViewChild("tagsContainer", { static: false })
	tagsContainer: ElementRef<HTMLElement>;

	@Input() item: ICatalogItem;
	@Input() title: string;
	@Input() description: string;
	@Input() isWidget: boolean;
	@Input() canAdd: boolean;
	@Input() canPreview: boolean;
	@Input() changedBy: string;
	@Input() typeName: string;
	@Input() addMargins = true;
	@Input() contextMenuId: string;
	@Input() set category(category: number) {
		if (!CommonUtil.isUndefined(category)) {
			this.headerColor = this.catalogService.getWidgetCategoryColor(category);
		}
	}
	@Input() set color(color: PageColor) {
		if (!CommonUtil.isUndefined(color)) {
			this.headerColor = UIUtil.numberToHexCode(color);
		}
	}

	@Output() onClickAdd = new EventEmitter<ICatalogAddInfo>();
	@Output() onClickDetails = new EventEmitter<ICatalogItem>();
	@Output() onClickPreview = new EventEmitter<ICatalogItem>();
	@Output() onClickAddTag = new EventEmitter<string>();
	@Output() contextMenuOpen = new EventEmitter<ICatalogItem>();

	itemId: string;
	lang: ILanguageLime;
	showMoreTags: boolean;
	headerColor: string;
	automationIdIdentifier: string;
	tooltip: string;

	constructor(
		languageService: LanguageService,
		private readonly catalogService: CatalogService,
		private readonly displayNamePipe: DisplayNamePipe,
	) {
		this.lang = languageService.getLanguage();
	}

	ngOnInit() {
		this.itemId = this.item.widgetId || this.item.data.id;
		this.automationIdIdentifier =
			"-" + StringUtil.formatTextForId(this.item.title, "item");
		this.tooltip = HtmlUtil.escapeStringForHtml(this.title);
	}

	setShowMoreTags() {
		const tagRowHeight = 29;
		this.showMoreTags =
			this.tagsContainer.nativeElement.scrollHeight > tagRowHeight;
	}

	get editedByText(): string {
		const lang = this.lang;
		if (PageUtil.isPrivate(this.item as IPage)) {
			return lang.format(lang.lastEdited);
		} else {
			return `${this.lang.lastEditedByHeader} ${this.displayNamePipe.transform(
				this.changedBy || this.item.data.changedByName,
			)}`;
		}
	}
}
