import { Component, OnInit } from "@angular/core";
import { SohoMessageService, SohoModalDialogRef } from "ids-enterprise-ng";
import {
	ArrayUtil,
	DialogButtonType,
	ITranslationItem,
	IWidgetSettingMetadata,
	IWidgetSize,
	StringUtil,
} from "lime";
import {
	AccessUtil,
	Constants,
	ContextService,
	EditModeService,
	EditModes,
	EntityCategory,
	EntityOperation,
	IEntityAccessDialogOptions,
	ILocalizationParameter,
	IPublishedWidgetItem,
	ISettingItem,
	IStringMapMap,
	IStringResponse,
	IStringToEntityLocalizationMap,
	IWidgetDefinition,
	IWidgetPublishInfo,
	IWidgetSettingMetadataEx,
	LanguageService,
	ModalDialogBase,
	ProgressService,
	WidgetService,
	WidgetTargets,
	WidgetUtil,
} from "lime/core";

interface IWidgetSettingItem {
	label: string;
	setting: IWidgetSettingMetadataEx;
	isEnabled: boolean;
	isVisible: boolean;
	isHidden?: boolean;
}

/**
 * Component for the dialog that is used to edit the publish configuration for a widget.
 */
@Component({
	templateUrl: "./widget-publish.html",
	styleUrls: ["./widget-publish.scss"],
})
export class WidgetPublishComponent extends ModalDialogBase implements OnInit {
	modalDialog: SohoModalDialogRef<WidgetPublishComponent>;
	item: IPublishedWidgetItem;
	definition: IWidgetDefinition;
	isPublished: boolean;
	/**
	 * If the publish dialog is opened from the banner area or from the banner catalog.
	 */
	isBanner: boolean;
	customized: IWidgetDefinition = {};
	category = EntityCategory.widgetLocalization;
	accessOptions: IEntityAccessDialogOptions;
	widgetTitleLength: number;
	widgetDescriptionLength: number;
	lang: ILanguageLime;
	tags: string[];
	isEditFromCatalog: boolean;

	/**
	 * Gets or sets a value that indicates if the widget supports settings or not.
	 */
	enableSettings: boolean;
	enableUserSettings: boolean;
	translationEnabled: boolean;
	isTitleEditDisabled: boolean;

	/**
	 * Gets or sets a value that indicates if the Permission tab should be displayed.
	 */
	enableAccess: boolean;
	settingsItems: IWidgetSettingItem[];

	localization: ILocalizationParameter;

	/**
	 * Wrapper for target state.
	 */
	widgetTarget: WidgetTargets;
	showDefault = false;
	showBanner = false;
	showMobile = false;
	showTargetOptions = false;
	isTargetMissing = false;

	defaultSize: IWidgetSize;
	maxSize: IWidgetSize;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private widgetService: WidgetService,
		private editModeService: EditModeService,
		private contextService: ContextService,
		private progressService: ProgressService,
	) {
		super("WidgetPublishComponent", messageService, languageService);
		this.lang = languageService.getLanguage();
		this.translationEnabled = this.contextService
			.getContext()
			.settings.isContentTranslationEnabled();
		this.widgetTitleLength = Constants.widgetTitleLength;
		this.widgetDescriptionLength = Constants.widgetDescriptionLength;
		this.isBanner = false;
	}

	get applyDisabled(): boolean {
		const isEmpty = (str: string): boolean => {
			return !(str && str.trim());
		};
		return (
			isEmpty(this.customized.title) ||
			isEmpty(this.customized.description) ||
			this.isTargetMissing ||
			this.isBusy
		);
	}

	ngOnInit(): void {
		this.progressService.setBusy(false);
		this.initModalDialog();
		this.enableAccess =
			this.editModeService.isMode(EditModes.widget) || this.isEditFromCatalog;

		const sourceDefinition = this.definition;
		this.isTitleEditDisabled =
			sourceDefinition && sourceDefinition.enableTitleEditDef === false;

		const item = this.item;
		const definition = item.definition;
		if (definition != null) {
			this.customized = definition;
			this.customized.title = this.customized.title.slice(
				0,
				this.widgetTitleLength,
			);
			if (
				!this.isPublished &&
				sourceDefinition.description === definition.description
			) {
				// Remove manifest description when unpublished and unchanged, i.e. first time only
				this.customized.description = "";
			}
			const tags = definition.tags ? definition.tags.split("#") : [];
			if (tags.length > 0) {
				tags.splice(0, 1); // Remove first empty
			}
			this.tags = tags;

			this.initLocalization();
			this.setSizeInformation(definition);
			this.setDefaultSize(this.defaultSize);
			this.initialize(definition, sourceDefinition);

			const accessOptions = AccessUtil.widgets(
				this.languageService,
				sourceDefinition.widgetId,
				definition.title,
				false,
			);
			accessOptions.access = item.access || [];
			accessOptions.showSwitch = false;
			this.accessOptions = accessOptions;
		}

		this.initializeTargets();
	}

	onTargetChange() {
		this.isTargetMissing = !this.widgetTarget.hasTarget();
	}

	close(): void {
		this.modalDialog.close();
	}

	apply() {
		this.customized.tags = this.tags
			.map((tag) => {
				return StringUtil.startsWith(tag, "#") ? tag : `#${tag}`;
			})
			.join("");
		const definitionCustom = this.customized;

		if (this.isTitleEditDisabled) {
			definitionCustom.enableTitleEdit = false;
		} else {
			const items = this.settingsItems;
			const titleSetting = items.shift();
			definitionCustom.enableTitleEdit = titleSetting.setting.isEnabled;
		}

		// Change so that we always set the options (even if they might not be visible they will have a value)
		this.setTargetsOnDefinition(
			definitionCustom,
			this.widgetTarget,
			this.definition,
		);

		const info: IWidgetPublishInfo = {
			publishedItem: {
				definition: definitionCustom,
				localization: this.localization
					.localizationMap as any as IStringToEntityLocalizationMap,
				access: this.accessOptions.access.filter(
					(access) => access.operation !== EntityOperation.Delete,
				),
			},
			isLocalizationChanged: this.isLocalizationsChanged(),
			isPublish: false,
		};

		if (this.isEditFromCatalog) {
			this.updatePublishedFromCatalog(info);
		} else {
			this.closeWithResult(DialogButtonType.Ok, info);
		}
	}

	onClickTab(tabName: string): void {
		if (tabName === "translations") {
			const widget = this.customized;
			const items = this.localization.translationOptions.items;
			items[0].defaultValue = widget.title;
			items[1].defaultValue = widget.description;
		}
		// Don't close the dialog on enter in the permissions tab due to being able to add entities with enter.
		this.modalDialog.suppressEnterKey(tabName === "accessLevel");
	}

	isTitleSetting(item: ISettingItem): boolean {
		// FUTURE There is some type confusion for IWidgetSettingMetadata vs ISettingItem.
		// This should be fixed but requires great care due to high regression risk.
		return (item.setting as any).name === Constants.settingsNameWidgetTitle;
	}

	isSettingItemDisabled(item: ISettingItem): boolean {
		if (!this.customized.enableSettings) {
			return true;
		}
		if (this.customized.isCatalogTitle && this.isTitleSetting(item)) {
			return true;
		}
		return false;
	}

	setDefaultSize(size: IWidgetSize): void {
		this.customized.defaultSize = size.cols + "," + size.rows;
	}

	private initializeTargets(): void {
		const settings = this.contextService.getContext().settings;
		const sourceDefinition = this.definition;
		const customDefinition = this.customized;
		// Create widget targets depending on targets and what features are enabled
		this.widgetTarget = WidgetUtil.createWidgetTarget(
			sourceDefinition,
			customDefinition,
			this.isBanner,
			settings,
		);
		this.showTargetOptions = this.widgetTarget.hasOptions();

		if (this.showTargetOptions) {
			this.showMobile = this.widgetTarget.showMobile;
			this.showDefault = this.widgetTarget.showDefault;
			this.showBanner = this.widgetTarget.showBanner;
		}
	}

	private setTargetsOnDefinition(
		customDef: IWidgetDefinition,
		targetInfo: WidgetTargets,
		sourceDef: IWidgetDefinition,
	) {
		// Set and remove all targets as some might have been removed from the source
		this.setTargetOnDefinition(
			Constants.targetMobile,
			customDef,
			targetInfo,
			sourceDef,
		);
		this.setTargetOnDefinition(
			Constants.targetBanner,
			customDef,
			targetInfo,
			sourceDef,
		);
		this.setTargetOnDefinition(
			Constants.targetContext,
			customDef,
			targetInfo,
			sourceDef,
		);
		this.setTargetOnDefinition(
			Constants.targetDefault,
			customDef,
			targetInfo,
			sourceDef,
		);

		// Validate that at least one target is set if source has targets
		if (
			sourceDef.targets &&
			StringUtil.isNullOrWhitespace(customDef.target) &&
			!customDef.targets
		) {
			this.logError("The widget has to have at least one target");
		}
		this.setDefaultTarget(customDef);
	}

	private setTargetOnDefinition(
		target: string,
		customDef: IWidgetDefinition,
		targetInfo: WidgetTargets,
		sourceDef: IWidgetDefinition,
	) {
		const isEnabled = targetInfo.isEnabled(target);
		const targets = customDef.targets;
		if (isEnabled) {
			if (targets) {
				if (!ArrayUtil.contains(targets, target)) {
					customDef.targets.push(target);
				}
			} else {
				customDef.targets = [target];
			}
			// If the source parent definition has default as target as well as mobile add default as well
			// if (sourceDef.targetsDef && ArrayUtil.contains(sourceDef.targetsDef, Constants.targetDefault)) {
			// 	customDef.targets.push(Constants.targetDefault);
			// }
		} else {
			const hasTargetEnabled = WidgetUtil.isTarget(customDef, target);
			if (hasTargetEnabled) {
				// Remove current target if it exists
				if (targets && ArrayUtil.contains(targets, target)) {
					ArrayUtil.remove(targets, target);
				}
			}
		}
	}

	private setDefaultTarget(definition: IWidgetDefinition) {
		// Add Default if default is a specified target in the source definition and it is not added
		const targets = definition.targets;
		if (ArrayUtil.contains(definition.targetsDef, Constants.targetDefault)) {
			if (targets && !ArrayUtil.contains(targets, Constants.targetDefault)) {
				targets.push(Constants.targetDefault);
			}
		}
	}

	private initLocalization(): void {
		const definition = this.item.definition;
		const language = this.languageService.getLanguage();
		const translationOptions = {
			items: [
				{
					name: "title",
					label: language.title,
					labelId: "lm-at-t-lbl",
					valueId: "lm-at-t",
					maxLength: Constants.widgetTitleLength,
					isPrimary: true,
					isRequired: true,
					defaultValue: definition.title,
				} as ITranslationItem,
				{
					name: "description",
					label: language.description,
					labelId: "lm-at-d-lbl",
					valueId: "lm-at-d",
					maxLength: Constants.widgetDescriptionLength,
					isTextArea: true,
					isRequired: true,
					defaultValue: definition.description || "",
				} as ITranslationItem,
			],
		};

		const localizationMap = this.item.localization || {};
		this.localization = {
			translationOptions: translationOptions,
			localizationMap: localizationMap as any as IStringMapMap,
			enablePortation: true,
		};
	}

	private updatePublishedFromCatalog(info: IWidgetPublishInfo): void {
		const publishDefinition = info.publishedItem.definition;

		// Extend widget with required data before update.
		publishDefinition.custom = {
			isCatalogTitle: publishDefinition.isCatalogTitle,
			isTitleLocked: this.definition.custom.isTitleLocked,
			title: publishDefinition.title,
			settings: this.definition.custom.settings,
			metadata: [],
		};
		if (publishDefinition.settings) {
			publishDefinition.settings.forEach((setting) => {
				publishDefinition.custom.metadata.push({
					name: setting.name,
					isEnabled: setting.isEnabled,
					isVisible: setting.isVisible,
				});
			});
		}
		publishDefinition.widgetId = this.definition.widgetId;
		publishDefinition.standardWidgetId = this.definition.standardWidgetId;
		publishDefinition.settings = null;

		this.setCanClose(false);
		this.setBusy(true);
		const self = this;
		this.widgetService.updatePublished(info.publishedItem).subscribe(
			() => {
				this.closeWithResult(DialogButtonType.Ok, info);
				this.setCanClose(true);
				this.setBusy(false);
			},
			(response: IStringResponse) => {
				self.widgetService.handleError(response);
				this.setCanClose(true);
				this.setBusy(false);
			},
		);
	}

	private enableItem(
		item: IWidgetSettingItem,
		name: string,
		definition: IWidgetDefinition,
	) {
		let isEnabled = true;
		let isVisible = true;
		let isHidden = false;
		if (definition) {
			definition = definition.original;
			const settings = definition.settings;
			if (settings) {
				const current = ArrayUtil.itemByProperty(
					settings,
					"name",
					name,
				) as IWidgetSettingMetadataEx;
				if (current) {
					if (current.isHidden === true) {
						isHidden = true;
					}
					if (current.isEnabled === false) {
						isEnabled = false;
					}
					if (current.isVisible === false) {
						isVisible = false;
					}
				}
			}
		}
		item.isEnabled = isEnabled;
		item.isVisible = isVisible;
		item.isHidden = isHidden;
	}

	private initialize(
		definition: IWidgetDefinition,
		sourceDefinition: IWidgetDefinition,
	) {
		const items: IWidgetSettingItem[] = [];
		const enableSettingsWhenPublished =
			sourceDefinition.enableSettingsWhenPublished !== false;

		this.enableSettings =
			sourceDefinition.enableSettingsDef && enableSettingsWhenPublished;
		this.enableUserSettings = enableSettingsWhenPublished;

		if (!this.isTitleEditDisabled) {
			items.push(this.createTitleSetting(definition));
		}

		const settings = definition.settings;
		if (settings && this.enableUserSettings) {
			const language = sourceDefinition.lang as ILanguageLime;
			for (const setting of settings) {
				items.push(this.createSetting(definition, setting, language));
			}
		} else {
			definition.enableSettings = false;
		}

		this.settingsItems = items;
	}

	private createSetting(
		definition: IWidgetDefinition,
		setting: IWidgetSettingMetadata,
		language: ILanguageLime,
	): IWidgetSettingItem {
		if (!definition.enableSettings) {
			setting.isEnabled = false;
			setting.isVisible = false;
		}

		if (setting.name === Constants.heroLinksSetting) {
			// Special case for Quick Links
			setting.isHidden = true;
			if (setting.labelId === Constants.heroLinksSetting) {
				setting.labelId = this.lang.manageQuickLinks;
			}
		}

		let isHidden = false;
		if (setting.isHidden) {
			setting.isVisible = false;
			isHidden = true;
		}

		const item = { setting: setting } as IWidgetSettingItem;
		item.isHidden = isHidden;
		item[WidgetUtil.labelProperty] = WidgetUtil.getTranslation(
			setting.labelId,
			language as ILanguageLime,
		);

		return item;
	}

	private createTitleSetting(
		definition: IWidgetDefinition,
	): IWidgetSettingItem {
		return {
			label: this.lang.title,
			setting: {
				name: Constants.settingsNameWidgetTitle,
				isEnabled: definition.enableTitleEdit && definition.enableSettings,
			} as IWidgetSettingMetadataEx,
			isEnabled: true,
			isVisible: true,
		};
	}

	private isLocalizationsChanged() {
		// FUTURE Consider this for optimization when updating a published widget
		return true;
	}

	private setSizeInformation(definition: IWidgetDefinition) {
		const standardSize = WidgetUtil.getStandardSize(definition);
		const maxSize = WidgetUtil.getMaxSize(definition);
		this.defaultSize = {
			cols: standardSize.columnSpan,
			rows: standardSize.rowSpan,
		};
		this.maxSize = { cols: maxSize.columnSpan, rows: maxSize.rowSpan };
	}
}
