import { Component, EventEmitter, Input, Output } from "@angular/core";
import { ArrayUtil, IAutocompleteEntity } from "lime";
import {
	CommonDataService,
	ContextService,
	CoreUtil,
	IUserListResponse,
	PrincipalType,
	Templates,
} from "lime/core";
import { ICatalogFilter, ICatalogUser } from "../catalog-core";

@Component({
	selector: "lm-catalog-owner-filter",
	templateUrl: "./owner-filter.component.html",
})
export class OwnerFilterComponent {
	@Input() filter: ICatalogFilter;
	@Input() ownerSearchModel: { inputText?: string; value?: ICatalogUser } = {
		value: {},
	};
	@Input() lang: ILanguageLime;
	@Input() isWidget: boolean;
	@Input() currentUser: ICatalogUser;

	@Output() filterChange = new EventEmitter<ICatalogFilter>();
	@Output() ownerSearchModelChange = new EventEmitter<{
		inputText?: string;
		value?: ICatalogUser;
	}>();

	isOwnedByFilterEnabled: boolean;
	ownerSearchSource: Function;
	ownerSearchTemplate: string;
	myItemsLabel: string;

	constructor(
		private readonly contextService: ContextService,
		private readonly commonDataService: CommonDataService,
	) {
		const context = this.contextService.getContext();
		this.isOwnedByFilterEnabled =
			context.settings.isOwnerFilterInCatalogsEnabled();
	}

	ngOnInit(): void {
		this.myItemsLabel = this.isWidget
			? this.lang.myWidgetsFilter
			: this.lang.myPagesFilter;
		this.initializeOwnerSearch();
	}

	onClickSelectOwnedBy(object: IAutocompleteEntity): void {
		const user = { name: object.label, id: object.value };
		this.ownerSearchModel = { inputText: object.label, value: user };
		this.filter.owner = user.id;
		this.emitChanges();
	}

	clearOwnedByUser(): void {
		this.filter.owner = null;
		this.ownerSearchModel = { value: {} };
		this.emitChanges();
	}

	emitFilterChange(): void {
		this.filterChange.emit(this.filter);
	}

	emitChanges(): void {
		this.ownerSearchModelChange.emit(this.ownerSearchModel);
		this.emitFilterChange();
	}

	private initializeOwnerSearch(): void {
		this.ownerSearchSource = (query: string, done: Function) => {
			this.commonDataService
				.searchUsers(query)
				.subscribe((response: IUserListResponse) => {
					const items = CoreUtil.getEntityArray(
						PrincipalType.User,
						response.content,
					);
					done(query, ArrayUtil.sortByProperty(items, "label"));
				});
		};
		this.ownerSearchTemplate = Templates.autocompleteEntity;
	}
}
