import { Component, OnInit } from "@angular/core";
import { SohoContextualActionPanelRef } from "ids-enterprise-ng";
import { ArrayUtil, CommonUtil, DialogService } from "lime";
import {
	CommonDataService,
	ContainerService,
	ContextService,
	CoreBase,
	IContext,
	IOperationResponse,
	IPageContainer,
	IPageData,
	IPageInstance,
	IServerSettings,
	IStringMap,
	IStringResponse,
	LanguageService,
	PageService,
	PageUtil,
	ProgressService,
	Toggle,
} from "lime/core";
import { DisplayNameService } from "scripts/lime/core/services/display-name.service";
import { ISortedInfo } from "./page-my-sortable.directive";

@Component({
	templateUrl: "./page-my.html",
	styleUrls: ["./page-my.scss"],
})
export class MyPagesComponent extends CoreBase implements OnInit {
	lang: ILanguageLime;
	pages: IPageInstance[] = [];
	activePage: IPageInstance;
	dialog: SohoContextualActionPanelRef<MyPagesComponent>;
	home: string;
	isHomepageSelectionEnabled: boolean;

	private readonly context: IContext;
	private pageContainer: IPageContainer;
	private isMobilePagesEnabled: boolean;
	private settings: IServerSettings;

	constructor(
		private dialogService: DialogService,
		private pageService: PageService,
		private progressService: ProgressService,
		private containerService: ContainerService,
		private commonDataService: CommonDataService,
		private displayNameService: DisplayNameService,
		languageService: LanguageService,
		contextService: ContextService,
	) {
		super("MyPagesComponent");
		this.lang = languageService.getLanguage();
		const context = contextService.getContext();
		this.settings = context.settings;
		this.isHomepageSelectionEnabled =
			context.settings.isSelectHomepageEnabled();
		this.isMobilePagesEnabled = context.settings.isMobilePagesEnabled();
		this.context = context;
	}

	ngOnInit() {
		const container = this.containerService.getContainer();
		if (container) {
			this.pageContainer = container;
			this.pages = container.pages;
			this.loadDisplayNames();
			this.getAndUpdateHome();
		}

		this.setBusy(false);
	}

	isPagePrivate(page: IPageInstance): boolean {
		return PageUtil.isPrivate(page);
	}

	showSettings(page: IPageInstance) {
		this.pageContainer.showPageInformation(page.id);
	}

	canOpenInCatalog(page: IPageInstance): boolean {
		return (
			page &&
			page.isPublished() &&
			page.isViewable &&
			this.context.settings.isPageCatalogEnabled()
		);
	}

	canEnableMobile(page: IPageInstance): boolean {
		if (!this.isMobilePagesEnabled || !page.isMobile || page.isMandatory) {
			return false;
		}
		return true;
	}

	isMobile(page: IPageInstance): boolean {
		return page.isMobile && this.settings.isMobilePage(page.id);
	}

	toggleMobile(page: IPageInstance, isEnable: boolean): void {
		const currentValue = this.isMobile(page);
		if (currentValue === isEnable) {
			return;
		}

		const mobilePages = this.settings.getMobilePages();
		if (isEnable) {
			// Enabled is the default so just remove the value
			delete mobilePages[page.id];
		} else {
			mobilePages[page.id] = Toggle.Disabled;
		}

		for (const pageId of Object.keys(mobilePages)) {
			if (!this.pageContainer.contains(pageId)) {
				delete mobilePages[pageId];
			}
		}

		this.settings.setMobilePages(mobilePages);
		this.saveSettings();
	}

	removePage(page: IPageInstance) {
		this.pageContainer.remove(page).subscribe(
			() => {
				this.closeIfEmpty();
			},
			(r: IOperationResponse) => {
				this.pageService.handleError(r);
			},
		);
	}

	deletePage(page: IPageInstance) {
		this.pageContainer.delete(page.id, page.title, false).subscribe(
			() => {
				this.closeIfEmpty();
			},
			(r: IOperationResponse) => {
				this.pageService.handleError(r);
			},
		);
	}

	setHome(page: IPageInstance) {
		if (this.isBusy()) {
			return;
		}
		this.setBusy(true);

		let home = this.home;
		const oldHome = home;
		if (oldHome === page.id) {
			home = "";
		} else {
			home = page.id;
		}

		this.context.settings.setStartPage(home);
		this.context.settings.saveUserSettings().subscribe(
			(r: IStringResponse) => {
				this.home = home;
				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.pageService.handleError(r);
				this.setBusy(false);
			},
		);
	}

	openInCatalog(page: IPageInstance) {
		this.pageService.showPageCatalog(page);
		this.close();
	}

	close() {
		this.dialog.close(null, true);
	}

	setActivePage(page: IPageInstance) {
		this.activePage = page;
	}

	copyToClipboard(): void {
		const page = this.activePage;
		const usedBy = !CommonUtil.isUndefined(page.popularity)
			? `Used by: ${page.popularity}, \n`
			: "";
		const ownerName = page.data.ownerName
			? `Owner name: ${page.data.ownerName}, \n`
			: "";
		const ownerId = page.data.ownerId
			? `Owner ID: ${page.data.ownerId}, \n`
			: "";
		const copyString =
			`Title: ${page.data.title}, \nPage ID: ${page.data.id}, \n${usedBy}${ownerName}${ownerId}` +
			`Description: ${page.data.description}, \nLast Edited: ${page.data.changeDate}`;

		this.dialogService.copyToClipboard({ copyData: copyString });
	}

	updatePageOrder(sortedInfo: ISortedInfo) {
		if (this.isBusy()) {
			return;
		}
		this.setBusy(true);

		const reOrderedPages = this.getNewOrder(sortedInfo);
		this.pageContainer.reorder(reOrderedPages).subscribe(
			() => {
				ArrayUtil.move(this.pages, sortedInfo.startIndex, sortedInfo.stopIndex);
				this.setBusy(false);
			},
			() => {
				sortedInfo.sortableElement.sortable("cancel");
				this.setBusy(false);
			},
		);
	}

	isBusy(): boolean {
		return this.progressService.isBusy();
	}

	getType(page: IPageInstance): string {
		const lang = this.lang;
		let typeName: string;
		if (page.isMandatory) {
			typeName = lang.mandatory;
		} else if (PageUtil.isPrivate(page)) {
			typeName = lang.private;
		} else if (page.data.isStandard) {
			typeName = lang.standardPage;
		} else {
			typeName = lang.publishedWidgetTag;
		}
		return typeName;
	}

	private closeIfEmpty() {
		if (!this.pages.length) {
			this.close();
		}
	}

	private setBusy(isBusy: boolean): void {
		this.progressService.setBusy(isBusy);
	}

	private loadDisplayNames() {
		const userIds = [];

		const addIdsForMissingNames = (
			data: IPageData,
			idProperty: string,
			nameProperty: string,
		) => {
			const id = data[idProperty];
			const name = data[nameProperty];
			if (id && !name) {
				userIds.push(id);
			}
		};

		const applyDisplayNames = (
			data: IPageData,
			idProperty: string,
			nameProperty: string,
			displayNames: IStringMap,
		) => {
			const id = data[idProperty];
			const name = displayNames[id];
			if (name) {
				data[nameProperty] = name;
			}
		};

		for (const page of this.pages) {
			if (page.isPublished()) {
				const data = page.data;
				addIdsForMissingNames(data, "changedBy", "changedByName");
				addIdsForMissingNames(data, "ownerId", "ownerName");
			}
		}

		if (userIds.length > 0) {
			this.displayNameService
				.getDisplayNames(userIds)
				.subscribe((displayNames) => {
					for (const page of this.pages) {
						if (page.isPublished()) {
							const data = page.data;
							applyDisplayNames(
								data,
								"changedBy",
								"changedByName",
								displayNames,
							);
							applyDisplayNames(data, "ownerId", "ownerName", displayNames);
						}
					}
				});
		}
	}

	private getNewOrder(sortedInfo: ISortedInfo): string[] {
		const pages = [...this.pages].map((page: IPageInstance) => {
			return page.id;
		});

		const movedPage = pages.splice(sortedInfo.startIndex, 1)[0];
		pages.splice(sortedInfo.stopIndex, 0, movedPage);

		return pages;
	}

	private getAndUpdateHome() {
		if (this.isHomepageSelectionEnabled) {
			this.home = this.context.settings.getStartPage();
		}
	}

	private saveSettings(): void {
		this.setBusy(true);
		this.settings.saveUserSettings().subscribe(
			() => {
				this.setBusy(false);
			},
			() => {
				this.setBusy(false);
			},
		);
	}
}
