import { Component, OnInit, ViewChild } from "@angular/core";
import {
	SohoColorPickerComponent,
	SohoMessageService,
	SohoModalDialogRef,
} from "ids-enterprise-ng";
import { DialogButtonType, ITranslationOptions, StringUtil } from "lime";
import {
	AccessUtil,
	Constants,
	ContextService,
	CoreUtil,
	EntityCategory,
	IContext,
	IEntityAccessDialogOptions,
	ILocalizationParameter,
	IOperationResponse,
	IPage,
	IPageConfig,
	IPageData,
	IPageDataResponse,
	IPageLink,
	IStringMapMap,
	IStringToEntityLocalizationMap,
	LanguageService,
	ModalDialogBase,
	PageService,
	ProgressService,
	Toggle,
	UIUtil,
} from "lime/core";

/**
 * Component class for the publish page dialog.
 */
@Component({
	templateUrl: "./page-publish.html",
	styleUrls: ["./page-publish.scss"],
})
export class PagePublishComponent extends ModalDialogBase implements OnInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;
	dialog: SohoModalDialogRef<PagePublishComponent>;
	page = {} as IPage;
	isPublished: boolean;
	accessOptions: IEntityAccessDialogOptions;
	lang: ILanguageLime;
	pageTitleLength;
	pageDescriptionLength;
	pageData: IPageData = {};
	translationEnabled: boolean;
	tags: string[];
	localization: ILocalizationParameter;
	category = EntityCategory.pageLocalization;
	pageColor = Constants.defaultColor;
	link: IPageLink = { title: "", url: "" };
	config: IPageConfig;
	enableMemo: boolean;
	isEditFromCatalog: boolean;
	colorpickerOptions = UIUtil.getPageColorPickerOptions();
	allowedMemoDuration = Constants.allowedMemoDuration;
	mobilePagesFeature = false;
	enableForMobile = true;

	private context: IContext;
	private tabOptions: any;
	private openTab: string;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		contextService: ContextService,
		private readonly pageService: PageService,
		private readonly progressService: ProgressService,
	) {
		super("PagePublishComponent", messageService, languageService);

		this.context = contextService.getContext();
		const settings = this.context.settings;
		this.translationEnabled = settings.isContentTranslationEnabled();
		this.mobilePagesFeature = settings.isMobilePagesEnabled();
		this.lang = languageService.getLanguage();
		this.pageTitleLength = Constants.pageTitleLength;
		this.pageDescriptionLength = Constants.pageDescriptionLength;
		this.tabOptions = { modalId: Constants.modalPagePublish };
	}

	ngOnInit(): void {
		this.progressService.setBusy(false);
		this.initModalDialog();
		const page = this.page;
		const pageData = CoreUtil.copy(page.data);
		this.pageData = pageData;

		// Add spaces to the tags becuase they look too strange in the UI like #Test#Sales#Yes
		// this.pageData.tags = lm.StringUtil.splitTagString(this.pageData.tags);
		this.tags = pageData.tags ? pageData.tags.split("#") : [];
		if (this.tags.length > 0) {
			this.tags.splice(0, 1); // Remove first empty
		}

		this.initLocalization();

		this.link = pageData.content.link || {};
		this.initializeConfig(pageData);
		this.accessOptions = AccessUtil.publishedPages(this.languageService, page);
		this.pageColor = UIUtil.numberToHexCode(this.pageData.color);
	}

	updateEnableMemo(isEnabled: boolean) {
		this.config.enableMemo = isEnabled ? 1 : 0;
	}

	initializeConfig(pageData: IPageData) {
		const pageDataConfig = pageData.config;
		this.config = {
			enableMemo: (pageDataConfig && pageDataConfig.enableMemo) || 0,
			memoDuration: (pageDataConfig && pageDataConfig.memoDuration) || 0,
			disableAnimation:
				(pageDataConfig && pageDataConfig.disableAnimation) || 0,
		};

		this.enableForMobile = this.getEnableMobileBoolean(pageDataConfig);
	}

	updateDisableAnimation(isDisabled: boolean) {
		this.config.disableAnimation = isDisabled ? 1 : 0;
	}

	canSave(): boolean {
		// Using manual validation due to issues with IDS form validation not triggering when showing / hiding page link.
		return !this.isBusy && this.isValid();
	}

	apply(): void {
		if (!this.canSave()) {
			return;
		}

		// Set title, tags and desc since these are generated from createSavePageData()
		const page = this.page;
		page.data.title = this.pageData.title;
		page.data.tags = this.tags
			.map((tag) => {
				return StringUtil.startsWith(tag, "#") ? tag : `#${tag}`;
			})
			.join("");
		page.data.description = this.pageData.description;
		page.data.color = UIUtil.hexCodeToNumber(
			this.colorpicker.getHexValue() as string,
		);
		if (this.link.enabled) {
			page.data.content.link = this.link;
		} else {
			delete page.data.content.link;
		}
		const enableMemo = this.config.enableMemo;
		page.data.config = {
			enableMemo: enableMemo,
			memoDuration: enableMemo ? this.config.memoDuration : 0,
			disableAnimation: enableMemo ? this.config.disableAnimation : 0,
			enableMobile: this.getMobileSaveValue(),
		};

		const pageRequest = {
			data: page.data,
			access: this.accessOptions.access,
			localization: this.localization
				.localizationMap as any as IStringToEntityLocalizationMap,
		} as IPage;

		// Updated edited page
		if (this.isEditFromCatalog) {
			const self = this;
			this.setBusy(true);
			this.setCanClose(false);
			this.pageService.updatePublished(pageRequest).subscribe(
				(r: IPageDataResponse) => {
					this.setBusy(false);
					this.setCanClose(true);
					this.closeWithResult(DialogButtonType.Ok, pageRequest);
				},
				(r: IOperationResponse) => {
					self.pageService.handleError(r);
					this.setBusy(false);
					this.setCanClose(true);
				},
			);
		} else {
			this.closeWithResult(DialogButtonType.Ok, pageRequest);
		}
	}

	onClickTab(tabName: string): void {
		this.openTab = tabName;
		if (tabName === "translations") {
			const data = this.pageData;
			const items = this.localization.translationOptions.items;
			items[0].defaultValue = data.title;
			items[1].defaultValue = data.description;
		}
	}

	formatMemoDuration(value: number): string {
		return value === 0 ? this.lang.off : `${value}`;
	}

	private getMobileSaveValue(): number {
		if (!this.context.settings.isMobilePagesEnabled()) {
			return Toggle.Default; // Unknown value
		}
		if (this.enableForMobile === false) {
			return Toggle.Disabled;
		}
		return Toggle.Enabled;
	}
	private getEnableMobileBoolean(pageConfig: IPageConfig): boolean {
		if (!pageConfig) {
			return true;
		}
		return !Toggle.isDisabled(pageConfig.enableMobile);
	}

	private initLocalization(): void {
		const localizationMap = this.page.localization
			? CoreUtil.copy(this.page.localization)
			: {};
		this.localization = {
			translationOptions: this.createTranslationOptions(),
			localizationMap: localizationMap as any as IStringMapMap,
			enablePortation: true,
		};
	}

	private createTranslationOptions(): ITranslationOptions {
		const language = this.languageService.getLanguage();
		const pageData = this.pageData;
		return {
			items: [
				{
					name: "title",
					label: language.title,
					labelId: "lm-at-t-lbl",
					valueId: "lm-at-t",
					maxLength: Constants.pageTitleLength,
					defaultValue: pageData.title,
					isRequired: true,
				},
				{
					name: "description",
					label: language.description,
					labelId: "lm-at-d-lbl",
					valueId: "lm-at-d",
					maxLength: Constants.pageDescriptionLength,
					isTextArea: true,
					defaultValue: pageData.description,
					isRequired: true,
				},
			],
		};
	}

	private isValid(): boolean {
		const data = this.pageData;
		const link = this.link;
		return !!(
			data.title &&
			data.description &&
			(!link.enabled || (link.title && link.url))
		);
	}
}
