import {
	Directive,
	ElementRef,
	EventEmitter,
	NgZone,
	Output,
} from "@angular/core";

export interface ISortable extends JQuery {
	sortable?: (arg: {} | string) => {};
}

export interface ISortedInfo {
	startIndex: number;
	stopIndex: number;
	sortableElement: ISortable;
}

@Directive({
	selector: "[my-pages-sortable]",
})
export class PageMySortableDirective {
	@Output() onSorted = new EventEmitter<ISortedInfo>();

	constructor(
		private readonly zone: NgZone,
		element: ElementRef,
	) {
		const sortableElement: ISortable = $(element.nativeElement);
		let startIndex: number;
		const options = {
			items: "> li:not(.unsortable)",
			opacity: 0.8,
			placeholder: "lm-my-pages-placeholder lm-hdr-bg",
			tolerance: "pointer",
			cursor: "move",
			axis: "x",
			delay: 100,
			start: (event: Event, ui: { item: JQuery }) => {
				startIndex = ui.item.index();
			},
			update: (event: Event, ui: { item: JQuery }) => {
				const stopIndex = ui.item.index();
				this.zone.run(() => {
					this.onSorted.emit({ startIndex, stopIndex, sortableElement });
				});
			},
		};

		sortableElement.sortable(options);
	}
}
