import { Component, OnInit, ViewChild } from "@angular/core";
import {
	SohoColorPickerComponent,
	SohoModalDialogRef,
} from "ids-enterprise-ng";
import { DialogButtonType, IAutocompleteEntity, IDialogResult } from "lime";
import {
	Constants,
	ContextService,
	CoreBase,
	IOperationResponse,
	IPageData,
	IPageInstance,
	IPageResponse,
	IServerSettings,
	LanguageService,
	ModalDialogBase,
	PageDataValidator,
	PageService,
	ProgressService,
	UIUtil,
} from "lime/core";

@Component({
	templateUrl: "./page-new.html",
})
export class NewPageComponent extends ModalDialogBase implements OnInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;
	modalDialog: SohoModalDialogRef<NewPageComponent>;
	lang: ILanguageLime;
	pageTitleLength = Constants.pageTitleLength;
	pageDescriptionLength = Constants.pageDescriptionLength;
	newPage: IPageData = {};
	pageColor = Constants.defaultColor;
	nextSortOrder: number;
	maxUserPage: number;
	isDev: boolean;
	colorpickerOptions = UIUtil.getPageColorPickerOptions();

	constructor(
		languageService: LanguageService,
		private pageService: PageService,
		private progressService: ProgressService,
	) {
		super("NewPageComponent");
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		this.initModalDialog();
		this.progressService.setBusy(false);
	}

	create() {
		if (this.isBusy) {
			return;
		}

		this.canClose = false;

		const page = this.newPage;
		page.sortOrder = this.nextSortOrder;
		const color = UIUtil.hexCodeToNumber(this.colorpicker.getHexValue());
		if (color !== Constants.defaultColorNumber) {
			page.color = color;
		}

		const isValid = new PageDataValidator().validate(page);
		if (!isValid) {
			return;
		}

		if (this.isDev) {
			this.setCanClose(true);
			this.closeWithResult(DialogButtonType.Ok, page);
			return;
		}

		this.setBusy(true);
		const self = this;
		this.pageService.createPrivate(page).subscribe(
			(response: IPageResponse) => {
				self.closeWithResult(DialogButtonType.Ok, response);
			},
			(response: IOperationResponse) => {
				this.pageService.handleCreatePageError(response, this.maxUserPage);
				self.setCanClose(true);
				self.setBusy(false);
			},
		);
	}
}

@Component({
	templateUrl: "./page-copy.html",
})
export class CopyPageComponent extends CoreBase {
	dialog: SohoModalDialogRef<CopyPageComponent>;
	lang: ILanguageLime;
	newPage: IPageData;
	pageTitleLength = Constants.pageTitleLength;
	private validator = new PageDataValidator(true);

	constructor(languageService: LanguageService) {
		super("CopyPageComponent");
		this.lang = languageService.getLanguage();
	}

	copy(): void {
		if (!this.validator.validate(this.newPage)) {
			return;
		}

		const result: IDialogResult = {
			value: this.newPage,
			button: DialogButtonType.Ok,
		};
		this.dialog.close(result);
	}

	close(): void {
		this.dialog.close();
	}
}

@Component({
	templateUrl: "./page-user-settings.html",
	styleUrls: ["./page-user-settings.scss"],
})
export class PageUserSettingsComponent extends CoreBase {
	dialog: SohoModalDialogRef<PageUserSettingsComponent>;
	orderedSettings: IAutocompleteEntity[];
	lang: ILanguageLime;
	maxUserPages: string;
	maxWidgetsOnPage: string;

	private readonly settings: IServerSettings;

	constructor(
		private readonly contextService: ContextService,
		languageService: LanguageService,
	) {
		super("PageUserSettingsComponent");

		this.settings = contextService.getContext().settings;
		this.lang = languageService.getLanguage();
		this.orderedSettings = this.createOrderedSettingsObject();
		this.setMaxEntityLabels();
	}

	close(): void {
		this.dialog.close();
	}

	/**
	 * Creates a settings array with translated content.
	 */
	private createOrderedSettingsObject(): IAutocompleteEntity[] {
		if (this.contextService.isMobile) {
			return this.orderedCommonSettings();
		} else {
			return [
				...this.orderedStandardSettings(),
				...this.orderedCommonSettings(),
			];
		}
	}

	private orderedStandardSettings(): IAutocompleteEntity[] {
		return [
			{
				info: "isPrivatePagesEnabled",
				label: this.lang.enablePrivatePages,
				value: this.settings.isPrivatePagesEnabled(),
			},
			{
				info: "isPageCatalogEnabled",
				label: this.lang.enablePageCatalog,
				value: this.settings.isPageCatalogEnabled(),
			},
			{
				info: "isPublicPageAddEnabled",
				label: this.lang.enablePublicPageAdd,
				value: this.settings.isPublicPageAddEnabled(),
			},
			{
				info: "isPublicPageCopyEnabled",
				label: this.lang.enablePublicPageCopy,
				value: this.settings.isPublicPageCopyEnabled(),
			},
			{
				info: "isPagePublishEnabled",
				label: this.lang.enablePagePublish,
				value: this.settings.isPagePublishEnabled(),
			},
			{
				info: "isPageExportEnabled",
				label: this.lang.enablePageExport,
				value: this.settings.isPageExportEnabled(),
			},
			{
				info: "isPageImportEnabled",
				label: this.lang.enablePageImport,
				value: this.settings.isPageImportEnabled(),
			},
			{
				info: "isSelectHomepageEnabled",
				label: this.lang.selectionOfHomepage,
				value: this.settings.isSelectHomepageEnabled(),
			},
			{
				info: "isOwnerFilterInCatalogsEnabled",
				label: this.lang.ownerFilterInCatalogs,
				value: this.settings.isOwnerFilterInCatalogsEnabled(),
			},
			{
				info: "isBannerWidgetEditEnabled",
				label: this.lang.editBannerWidgets,
				value: this.settings.isBannerWidgetEditEnabled(),
			},
			{
				info: "isWidgetPublishEnabled",
				label: this.lang.enableWidgetPublish,
				value: this.settings.isWidgetPublishEnabled(),
			},
		];
	}

	private orderedCommonSettings(): IAutocompleteEntity[] {
		return [
			{
				info: "isMobilePagesEnabled",
				label: this.lang.mobilePages,
				value: this.settings.isMobilePagesEnabled(),
			},
			{
				info: "isMobileWidgetsEnabled",
				label: this.lang.mobileWidgets,
				value: this.settings.isMobileWidgetsEnabled(),
			},
			{
				info: "isDisplayRestrictedWidgetsOnPageEnabled",
				label: this.lang.enableRestrictedWidgetsOnPage,
				value: this.settings.isDisplayRestrictedWidgetsOnPageEnabled(),
			},
		];
	}

	private setMaxEntityLabels() {
		if (!this.contextService.isMobile) {
			this.maxUserPages = this.lang.format(
				this.lang.maxUserPages,
				this.settings.getMaxUserPageCount(),
			);
			this.maxWidgetsOnPage = this.lang.format(
				this.lang.maxWidgetsOnPage,
				this.settings.getMaxWidgetsOnPageCount(),
			);
		}
	}
}

/**
 * Component for selecting page to which to add widget added externally via API
 */
@Component({
	templateUrl: "./page-select.html",
})
export class SelectPageComponent extends CoreBase {
	dialog: SohoModalDialogRef<SelectPageComponent>;
	pages: IPageInstance[];
	isNewPageAllowed: boolean;
	selectedPage;
	createNew = false;
	lang: ILanguageLime;

	constructor(
		languageService: LanguageService,
		private progressService: ProgressService,
	) {
		super("SelectPageComponent");
		this.lang = languageService.getLanguage();
		this.progressService.setBusy(false);
	}

	close() {
		this.dialog.close();
	}

	select() {
		const result = { button: DialogButtonType.Ok } as IDialogResult;

		if (this.createNew) {
			result.value = Constants.selectNewPrivate;
		} else if (this.selectedPage) {
			result.value = this.selectedPage;
		}

		this.dialog.close(result);
	}
}
