import {
	ChangeDetectorRef,
	Component,
	Input,
	OnDestroy,
	OnInit,
	ViewChild,
	ViewContainerRef,
} from "@angular/core";
import {
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
} from "ids-enterprise-ng";
import { ArrayUtil, CommonUtil, DialogButtonType } from "lime";
import {
	Constants,
	ContainerService,
	ContextService,
	CoreBase,
	CoreUtil,
	EditModeService,
	EditModes,
	IAddWidgetInfo,
	ICatalogAddItem,
	ICatalogOptions,
	ICommandBarAction,
	IEditMode,
	IEditableWidget,
	IHomepageSettings,
	IOperationResponse,
	IPageData,
	IPageDataDialogResult,
	IPageDataResponse,
	IPageInstance,
	IWidget,
	IWidgetDefinition,
	IWidgetEditData,
	IWidgetInfo,
	IWidgetLayout,
	LanguageService,
	LazyTypeService,
	PageService,
	PageUtil,
	UIUtil,
	WidgetService,
	WidgetUtil,
} from "lime/core";
import { Observable } from "rxjs";

const BANNER_MAX_COUNT = 4;

@Component({
	selector: "lm-page-edit",
	templateUrl: "./page-edit.html",
	styleUrls: ["./page-edit.scss"],
})
export class PageEditComponent extends CoreBase implements OnInit, OnDestroy {
	@Input() currentPage: IPageInstance;
	@Input() isHidden: boolean;

	@ViewChild("dialogPlaceholder", { read: ViewContainerRef, static: false })
	dialogPlaceholder: ViewContainerRef;

	lang: ILanguageLime;
	widgets: IEditableWidget[];
	bannerWidgets: IEditableWidget[] = [];
	bannerContainerStyle: {};
	bannerColor: string;
	showPasteBanner = false;
	currentColumns;
	isBannerOn = false;
	isBannerEditable = false;
	pageEditActive: boolean;
	headerColor: string;
	isBusy = false;
	updatedPageData: IPageData;
	widgetEditData: IWidgetEditData;

	private homepage: JQuery;
	private homepageSettings: IHomepageSettings;
	private clipboardWidget: IWidget;
	private isSettingsOpen: boolean;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly editModeService: EditModeService,
		private readonly contextService: ContextService,
		private readonly lazyTypeService: LazyTypeService,
		private readonly widgetService: WidgetService,
		private readonly toastService: SohoToastService,
		private readonly chRef: ChangeDetectorRef,
		private readonly containerService: ContainerService,
		private readonly sohoModalDialogService: SohoModalDialogService,
		private readonly pageService: PageService,
	) {
		super("PageEditComponent", messageService, languageService);

		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		this.initialize();
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");
		this.currentPage = null;
		this.widgets = null;
		this.bannerWidgets = null;
	}

	isEmpty(): boolean {
		return !this.hasWidgets() && (!this.isBannerOn || !this.hasBanners());
	}

	showEditDiv(): boolean {
		return this.hasWidgets() || this.hasBanners();
	}

	showBannerAdd(): boolean {
		return this.isBannerEditable && !this.hasBanners();
	}

	showBannerNotEditable(): boolean {
		return !this.isBannerEditable && this.hasBanners();
	}

	showBannerPlaceholder(): boolean {
		return (
			this.isBannerEditable && this.hasBanners() && !this.isBannerMaxCount()
		);
	}

	hasWidgets(): boolean {
		const widgets = this.widgets;
		return widgets && widgets.length > 0;
	}

	hasBanners(): boolean {
		const banners = this.bannerWidgets;
		return banners && banners.length > 0;
	}

	showWidgetPlaceholder(): boolean {
		return this.hasWidgets() || (this.isBannerOn && this.hasBanners());
	}

	close() {
		this.stopEdit(false);
	}

	save() {
		this.stopEdit(true);
	}

	showAsRestricted(widget: IEditableWidget): boolean {
		if (!widget.isRestricted) {
			return false;
		}
		return true;
	}

	onWidgetDropped(widgetDroppedInfo: {
		widget?: IEditableWidget;
		isBannerPlaceholder?: boolean;
	}) {
		const editData = this.widgetEditData;
		const droppableId = widgetDroppedInfo.widget
			? widgetDroppedInfo.widget.elementId
			: null;
		const draggableId = editData.elementId;

		const widgetSourceArray = ArrayUtil.containsByProperty(
			this.widgets,
			"elementId",
			draggableId,
		)
			? this.widgets
			: this.bannerWidgets;
		const isBannerSource = widgetSourceArray === this.bannerWidgets;

		const fromIndex = ArrayUtil.indexByProperty(
			widgetSourceArray,
			"elementId",
			draggableId,
		);
		let toIndex = ArrayUtil.indexByProperty(
			widgetSourceArray,
			"elementId",
			droppableId,
		);

		const isInternalPlaceholderDrop =
			!droppableId && isBannerSource === widgetDroppedInfo.isBannerPlaceholder;
		if (isInternalPlaceholderDrop) {
			toIndex = widgetSourceArray.length - 1;
		}

		const isContainerChange = toIndex === -1;

		if (!isContainerChange) {
			ArrayUtil.move(widgetSourceArray, fromIndex, toIndex);
			this.chRef.detectChanges();
			this.refreshLayout();
		} else if (editData.allowContainerChange) {
			if (!isBannerSource && this.isBannerMaxCount()) {
				return;
			}
			const widgetTargetArray = isBannerSource
				? this.widgets
				: this.bannerWidgets;
			const widget: IEditableWidget = ArrayUtil.itemByProperty(
				widgetSourceArray,
				"elementId",
				draggableId,
			);

			ArrayUtil.remove(widgetSourceArray, widget);

			let colSpan = widget.layout.columnSpan;
			if (isBannerSource) {
				this.updateBannerWidths(colSpan);
			} else {
				colSpan = this.getBannerWidth(colSpan);
				widget.layout.columnSpan = colSpan;
				widget.layout.rowSpan = 1;
				this.updateBannerWidths(colSpan, true);
			}

			widgetTargetArray.push(widget);

			if (droppableId) {
				toIndex = ArrayUtil.indexByProperty(
					widgetTargetArray,
					"elementId",
					droppableId,
				);
				ArrayUtil.move(
					widgetTargetArray,
					widgetTargetArray.length - 1,
					toIndex,
				);
			}

			widget.containerChangeInfo.isBanner = !isBannerSource;

			setTimeout(() => {
				this.chRef.detectChanges();
				this.refreshLayout();
			}, 1);
		}
	}

	onWidgetResized(isBanner?: boolean) {
		const editData = this.widgetEditData;
		const widgets = isBanner ? this.bannerWidgets : this.widgets;
		const editElementId = editData.elementId;
		if (
			CommonUtil.isUndefined(editData.elementId) ||
			CommonUtil.isUndefined(editData.widgetLayout) ||
			!ArrayUtil.containsByProperty(widgets, "elementId", editElementId)
		) {
			return;
		}

		const widget = ArrayUtil.itemByProperty(
			widgets,
			"elementId",
			editElementId,
		);
		const hasChanged =
			widget.layout.columnSpan !== editData.widgetLayout.columnSpan;
		widget.layout = editData.widgetLayout;

		if (isBanner && hasChanged) {
			this.resizeAffectedBanner(editData);
		}

		if (isBanner) {
			this.chRef.detectChanges();
		}
		this.refreshLayout();
	}

	deleteWidget(widget: IEditableWidget) {
		// TODO Destroy widget component?

		// Destroy widget scope and remove widget.
		// const element = $(`#${widget.elementId}`);
		// if (element.length > 0) {
		// 	angular.element($(`#${widget.elementId}`)).scope().$destroy();
		// }

		ArrayUtil.remove(this.widgets, widget);

		// Need to trigger it manually here since scope doesn't react to event.
		setTimeout(() => {
			this.refreshLayout();
		}, 1);
	}

	deleteBannerWidget(widget: IEditableWidget) {
		// TODO Destroy widget component?

		// const element = $(`#${widget.elementId}`);
		// if (element.length > 0) {
		// 	angular.element($(`#${widget.elementId}`)).scope().$destroy();
		// }

		ArrayUtil.remove(this.bannerWidgets, widget);
		this.updateBannerWidths(widget.layout.columnSpan);

		setTimeout(() => {
			this.refreshLayout();
		}, 1);
	}

	getLayoutClasses(widget: IEditableWidget): string {
		return widget.layout ? WidgetUtil.getLayoutClasses(widget.layout) : "";
	}

	addBannerFromCatalog() {
		if (this.currentColumns < 4) {
			this.showMessage(
				this.lang.unableToAddWidget,
				this.lang.bannerEditDisabled1 + " " + this.lang.bannerEditDisabled2,
			);
		} else if (this.isBannerMaxCount()) {
			this.showMessage(
				this.lang.unableToAddWidget,
				this.lang.maxBannerCountMessage,
			);
		} else {
			this.addWidgetFromCatalog(true);
		}
	}

	pasteBannerWidget(): void {
		if (this.currentColumns < 4) {
			this.showMessage(
				this.lang.unableToAddWidget,
				this.lang.bannerEditDisabled1 + " " + this.lang.bannerEditDisabled2,
			);
		} else if (this.isBannerMaxCount()) {
			this.showMessage(
				this.lang.unableToAddWidget,
				this.lang.maxBannerCountMessage,
			);
		} else {
			this.pasteWidget(true);
		}
	}

	getBannerLayoutClasses(widget: IEditableWidget): string {
		let layoutClasses = widget.layout
			? WidgetUtil.getLayoutClasses(widget.layout)
			: "";

		if (this.bannerWidgets.length === 2) {
			layoutClasses += " banner-max-width-three";
		} else if (this.bannerWidgets.length === 3) {
			layoutClasses += " banner-max-width-two";
		} else {
			layoutClasses += " banner-no-resize";
		}

		return layoutClasses;
	}

	addWidgetFromCatalog(isBanner = false) {
		const self = this;
		const addCallback = (addItem: ICatalogAddItem) => {
			const widgetInfo: IWidgetInfo = addItem.item;
			const addWidgetItem: IAddWidgetInfo = {
				isBanner: isBanner,
				byRef: addItem.byRef,
				widgetInfo: widgetInfo,
				isDuplicate: addItem.isDuplicate,
			};
			self.addWidget(addWidgetItem, addItem.busyCallback);
		};
		const republishCallback = (updatedDefinition: IWidgetDefinition) => {
			this.widgets.forEach((widget) => {
				if (widget.id === updatedDefinition.widgetId) {
					widget.title = updatedDefinition.title;
				}
			});
		};

		const options = {
			isBanner: isBanner,
			bannerWidgetCount: this.bannerWidgets.length,
			addCallback: addCallback,
			republishCallback: republishCallback,
		} as ICatalogOptions;

		this.lazyTypeService.injectLazyService("CatalogStartService").then(
			(service) => {
				service
					.openWidgetCatalog(options, this.dialogPlaceholder)
					.subscribe(() => {
						// Since widgets might have been updated via the catalog, some data must be updated.
						const widgetsWithCorrectData = this.currentPage.widgets;
						this.widgets.forEach((widget) => {
							widgetsWithCorrectData.forEach((widgetCorrect) => {
								if (widgetCorrect.data.instanceId === widget.instanceId) {
									widget.elementId = widgetCorrect.elementId;
								}
							});
						});
					});
			},
			(e) => {
				this.logError(
					"Failed to resolve CatalogStartService " + JSON.stringify(e),
				);
			},
		);
	}

	private setEditModeActions(editMode: IEditMode): void {
		const lang = this.lang;
		const self = this;
		const page = this.currentPage;

		const entityTitle = this.pageService.getPageTitleLocalizedOrDefault(page);
		const colorNumber = page.data.color || Constants.defaultColorNumber;
		const headerColor = UIUtil.numberToHexCode(colorNumber);

		editMode.entityTitle = entityTitle;
		editMode.headerColor = headerColor;
		editMode.actions = [
			{
				text: lang.cancel,
				icon: "close-cancel",
				cssClass: "e2e-editPageCancel",
				id: "lmEditPageCancel",
				execute: () => {
					self.close();
				},
			},
			{
				text: lang.save,
				id: "lmEditPageSave",
				icon: "save",
				cssClass: "e2e-editPageSave",
				execute: () => {
					self.save();
				},
			},
		];
		const secondaryActions: ICommandBarAction[] = [
			{
				text: lang.addWidget,
				id: "lmAddWidget",
				icon: "add",
				execute: () => {
					self.addWidgetFromCatalog();
				},
			},
		];

		const isBannerEnabled = this.isBannerOn && this.isBannerEditable;
		if (isBannerEnabled) {
			secondaryActions.push({
				text: lang.addHeroWidget,
				id: "lmAddBannerWidget",
				icon: "add",
				execute: () => {
					self.addBannerFromCatalog();
				},
			});
		}
		if (this.currentPage.isEditable && !this.currentPage.isPublished()) {
			secondaryActions.push({
				text: lang.pageSettings,
				icon: "settings",
				id: "lmPageSettings",
				hasSeparator: true,
				execute: () => {
					self.showPageSettings();
				},
			});
		}
		if (this.widgetService.hasClipboardWidget()) {
			const clipboardWidget = this.widgetService.getClipboardWidget();

			if (clipboardWidget.isMultiTarget || !clipboardWidget.isBanner) {
				secondaryActions.push({
					text: lang.pasteWidget,
					icon: "paste",
					id: "lmPasteWidget",
					execute: () => {
						self.pasteWidget();
					},
				});
			}

			if (
				isBannerEnabled &&
				(clipboardWidget.isMultiTarget || clipboardWidget.isBanner)
			) {
				this.showPasteBanner = true;
				secondaryActions.push({
					text: lang.pasteBannerWidget,
					icon: "paste",
					id: "lmPasteBannerWidget",
					execute: () => {
						self.pasteBannerWidget();
					},
				});
			}
		}
		editMode.secondaryActions = secondaryActions;
	}

	private initialize() {
		this.widgets = null;
		this.bannerWidgets = null;
		const settings = this.contextService.getContext().settings;
		const mode = this.editModeService.current;
		if (mode && mode.isActive && mode.mode === EditModes.layout) {
			this.isBannerOn = settings.isFeatureHeroWidget();
			this.isBannerEditable = settings.isBannerWidgetEditEnabled();
			this.setEditModeActions(mode);
		}

		const editableWidgets: IEditableWidget[] = [];
		const page = this.currentPage;
		const widgets = page.widgets;
		this.bannerWidgets = [];

		for (const widget of widgets) {
			if (widget.isBanner()) {
				this.bannerWidgets.push(this.createEditableWidget(widget));
			} else {
				editableWidgets.push(this.createEditableWidget(widget));
			}
		}

		this.setBannerColors(page.data.color);

		// Setup responsive behavior
		const homepage = $(".page-edit div.homepage");
		this.homepage = homepage;
		PageUtil.addHomepageControl(homepage, settings.isAnimationEnabled());
		const homepageData: any = homepage.data("homepage");
		this.homepageSettings = homepageData.settings;
		this.widgetEditData = {
			homepageSettings: this.homepageSettings,
		};
		this.pageEditActive = true;
		const self = this;
		// Refresh manually first time to get correct width of container, and re-calculate toolbar buttons visibility
		setTimeout(() => {
			self.refreshLayout();
		}, 1);

		this.widgets = editableWidgets;
	}

	private resizeAffectedBanner(editData: IWidgetEditData) {
		const otherBanners = this.bannerWidgets.filter(
			(banner: IEditableWidget) => {
				return banner.elementId !== editData.elementId;
			},
		);

		if (!otherBanners || !otherBanners.length) {
			return;
		}

		let affectedBannerIndex = 0;
		if (otherBanners.length === 1) {
			// Know that the one other widget is to take remaining column space
			otherBanners[affectedBannerIndex].layout.columnSpan =
				4 - editData.widgetLayout.columnSpan;
		} else {
			if (editData.widgetLayout.columnSpan === 2) {
				// Widget was increased
				affectedBannerIndex = ArrayUtil.indexByProperty(
					otherBanners.map((banner: IEditableWidget) => {
						return banner.layout;
					}),
					"columnSpan",
					2,
				);

				otherBanners[affectedBannerIndex].layout.columnSpan--;
			} else {
				const resizedBannerIndex = ArrayUtil.indexByProperty(
					this.bannerWidgets,
					"elementId",
					editData.elementId,
				);
				if (resizedBannerIndex !== 2) {
					affectedBannerIndex = resizedBannerIndex;
				}
				otherBanners[affectedBannerIndex].layout.columnSpan++;
			}
		}

		const affectedBanner = otherBanners[affectedBannerIndex];
		this.homepage
			.prev()
			.find("[banner-id=" + affectedBanner.elementId + "]")
			.removeClass("double-width triple-width quad-width")
			.addClass(this.getBannerLayoutClasses(affectedBanner));

		this.homepage.trigger("resize.homepage", ["bannerResized"]);
	}

	private refreshLayout() {
		PageUtil.refreshHomepageLayout(
			this.homepage,
			this.contextService.getContext().settings.isAnimationEnabled(),
		);
	}

	private pasteWidget(isBannerPaste = false) {
		const lang = this.lang;
		if (
			this.widgets.length >=
			this.contextService.getContext().settings.getMaxWidgetsOnPageCount()
		) {
			this.showMessage(lang.unableToAddWidget, lang.maxWidgetsOnPageMessage);
			return;
		}

		const widgetService = this.widgetService;
		const context = this.currentPage.getWidgetParentContext();
		const clipboardWidget = widgetService.getClipboardWidget();
		clipboardWidget.addInfo.isBanner = isBannerPaste;
		widgetService.preLoadWidget(context, clipboardWidget.addInfo).subscribe(
			(widget: IWidget) => {
				this.addWidgetInternal(widget, false, isBannerPaste);
			},
			() => {
				this.showError(this.lang.unableToAddWidget, this.lang.brokenWidget);
			},
		);
	}

	private addWidget(addWidgetInfo: IAddWidgetInfo, busyCallback?: Function) {
		const lang = this.lang;
		const widgetsOnPage = this.widgets.length + this.bannerWidgets.length;
		if (
			widgetsOnPage >=
			this.contextService.getContext().settings.getMaxWidgetsOnPageCount()
		) {
			this.showMessage(lang.unableToAddWidget, lang.maxWidgetsOnPageMessage);
			if (busyCallback) {
				busyCallback();
			}
			return;
		}
		const context = this.currentPage.getWidgetParentContext();
		this.widgetService
			.preLoadWidget(context, addWidgetInfo, busyCallback)
			.subscribe(
				(widget: IWidget) => {
					WidgetUtil.applyTitleOverride(addWidgetInfo, widget);
					this.addWidgetInternal(widget, true, addWidgetInfo.isBanner);
				},
				() => {
					this.showError(lang.unableToAddWidget, lang.brokenWidget);
				},
			);
	}

	private addWidgetInternal(
		widget: IWidget,
		showToastConfirmation: boolean,
		isBanner: boolean,
	): void {
		let columnSpan = isBanner ? this.getBannerWidth() : 1;
		let rowSpan = 1;

		if (isBanner) {
			if (this.isBannerMaxCount()) {
				return;
			}
			this.updateBannerWidths(columnSpan, true);
		} else {
			const defaultSize = WidgetUtil.getStandardSize(widget.definition);
			columnSpan = defaultSize.columnSpan;
			rowSpan = defaultSize.rowSpan;
		}

		const layout: IWidgetLayout = {
			row: 0,
			rowSpan: rowSpan,
			column: 0,
			columnSpan: columnSpan,
		};
		const editableWidget = this.createEditableWidget(widget, layout);
		editableWidget.widget = widget;
		editableWidget.elementId = CommonUtil.random();
		if (isBanner) {
			this.bannerWidgets.push(editableWidget);
		} else {
			this.widgets.push(editableWidget);
		}
		setTimeout(() => {
			this.refreshLayout();
		}, 1);

		if (showToastConfirmation) {
			const lang = this.lang;
			let title = editableWidget.title;
			const widgetAddInfo = widget.addWidgetInfo;
			if (widgetAddInfo && widgetAddInfo.widgetInfo) {
				const widgetInfo = widgetAddInfo.widgetInfo;
				if (widgetInfo.title) {
					// Use the title from the catalog
					title = widgetInfo.title;
				}
			}
			this.toastService.show(
				CoreUtil.getToastOptions(
					lang.widgetAdded,
					lang.format(lang.titleAddedMessage, title),
				),
			);
		}
	}

	private getBannerWidth(sourceWidth?: number): number {
		switch (this.bannerWidgets.length) {
			case 0:
				return 4;
			case 1:
				if (!sourceWidth || sourceWidth === 4) {
					return 2;
				} else {
					return sourceWidth;
				}
			case 2:
				return sourceWidth && sourceWidth > 1 ? 2 : 1;
			case 3:
			default:
				return 1;
		}
	}

	private updateBannerWidths(columnSpanChange: number, isAdd?): void {
		const bannersOnPage = this.bannerWidgets.length;
		if (isAdd) {
			switch (columnSpanChange) {
				case 4:
					// First banner on page, no other has to adopt
					return;
				case 3:
					this.bannerWidgets[0].layout.columnSpan = 1;
					break;
				case 2:
					if (bannersOnPage === 1) {
						this.bannerWidgets[0].layout.columnSpan = 2;
					} else {
						for (const banner of this.bannerWidgets) {
							banner.layout.columnSpan = 1;
						}
					}
					break;
				case 1:
					// Shrink the last possible banner
					let bannerToShrink = this.bannerWidgets[0];
					for (const banner of this.bannerWidgets) {
						if (banner.layout.columnSpan > columnSpanChange) {
							bannerToShrink = banner;
						}
					}
					bannerToShrink.layout.columnSpan--;
					break;
			}
		} else {
			switch (columnSpanChange) {
				case 4:
					// No banner left on page
					return;
				case 3:
					// A three column banner can only exist when there are two banners. After delete only one left to take full space
					this.bannerWidgets[0].layout.columnSpan = 4;
					break;
				case 2:
					// After a two column banner has been removed, there can only be either one or two left
					if (bannersOnPage === 1) {
						this.bannerWidgets[0].layout.columnSpan = 4;
					} else {
						for (const banner of this.bannerWidgets) {
							banner.layout.columnSpan++;
						}
					}
					break;
				case 1:
					switch (bannersOnPage) {
						case 1:
							this.bannerWidgets[0].layout.columnSpan = 4;
							break;
						case 2:
							for (const banner of this.bannerWidgets) {
								if (banner.layout.columnSpan === 1) {
									banner.layout.columnSpan++;
								}
							}
							break;
						case 3:
							// Give the extra size to the first "primary" banner
							this.bannerWidgets[0].layout.columnSpan++;
							break;
					}
					break;
			}
		}
	}

	private createEditableWidget(
		widget: IWidget,
		layout?: IWidgetLayout,
	): IEditableWidget {
		const data = widget.data;
		const title = widget.title;

		let isMultiTarget = false;
		let isBannerEnabled = false;
		const definition = widget.definition;

		if (definition) {
			const targets = definition.targets;
			isBannerEnabled =
				definition.target === "banner" ||
				(targets && ArrayUtil.contains(targets, "banner"));
			isMultiTarget =
				targets &&
				ArrayUtil.contains(targets, "banner") &&
				ArrayUtil.contains(targets, "default");
		}

		const maxSize = WidgetUtil.getMaxSize(definition);

		return {
			title: title,
			layout: layout ? layout : CoreUtil.copy(data.layout),
			isPlaceholder: false,
			id: data.id,
			elementId: widget.elementId,
			instanceId: data.instanceId,
			containerChangeInfo: { isAllowed: isMultiTarget },
			isRestricted: widget.isBrokenByAccessDenied(),
			isBroken: widget.isBroken(),
			brokenMessage: WidgetUtil.getBrokenReason(this.lang, data.brokenReason),
			isBanner: widget.isBanner(),
			isBannerEnabled: isBannerEnabled,
			maxSize: maxSize,
			standardSize: WidgetUtil.getStandardSize(definition, maxSize),
		};
	}

	private stopEdit(isSave: boolean) {
		const homepage = this.homepage;

		if (isSave && this.updatedPageData) {
			this.setBusy(true);
			const self = this;
			this.savePageData(this.updatedPageData).subscribe(
				(response: IPageDataResponse) => {
					const pageData = response.content;
					const page = self.currentPage;
					PageUtil.copyValues(pageData, page.data);

					page.title = pageData.title;
					page.description = pageData.description;
					page.changeDate = pageData.changeDate;

					self.containerService.raiseChanged();
					self.destroyAndClose(homepage, isSave);
					self.setBusy(false);
				},
				(errorResponse: IOperationResponse) => {
					self.pageService.handleError(errorResponse);
					self.setBusy(false);
				},
			);
			return;
		}

		this.destroyAndClose(homepage, isSave);
	}

	private showPageSettings() {
		if (this.isSettingsOpen) {
			return;
		}
		this.isSettingsOpen = true;

		const page = CoreUtil.copy(this.currentPage);
		if (this.updatedPageData) {
			page.data = this.updatedPageData;
		}
		const self = this;
		this.lazyTypeService.loadLazyModule().then(({ PageSettingsComponent }) => {
			const dialog = this.sohoModalDialogService
				.modal(PageSettingsComponent, this.dialogPlaceholder)
				.id("lm-p-set-mdl")
				.title(this.lang.pageSettings)
				.trigger("immediate")
				.afterClose((r: IPageDataDialogResult) => {
					this.isSettingsOpen = false;
					if (r && r.button === DialogButtonType.Ok) {
						const pageData = r.value.pageData;
						this.updatedPageData = pageData;

						if (r.value.colorChanged) {
							this.setBannerColors(pageData.color);
						}

						self.editModeService.updateEditModeContext({
							entityTitle: pageData.title,
							headerColor: UIUtil.numberToHexCode(pageData.color, false),
						});
					}
				});
			dialog
				.apply((component: any) => {
					component.modalDialog = dialog;
					component.parameter = page;
					component.saveDataOnClose = false;
				})
				.open();
		});
	}

	private setBannerColors(color: number): void {
		this.bannerContainerStyle = UIUtil.colorToBackgroundStyle(color, true);
		this.bannerColor = UIUtil.numberToRgba(color, 0.8);
	}

	private setBusy(isBusy: boolean): void {
		this.isBusy = isBusy;
	}

	private destroyAndClose(
		homepage: JQuery<HTMLElement>,
		isSave: boolean,
	): void {
		const updatedWidgets = this.widgets.slice(0);

		if (isSave) {
			const widgetElements = homepage.find(".widget").not(".placeholder");
			for (let i = 0; i < widgetElements.length; i++) {
				const widgetLayout = PageUtil.getLayout(
					$(widgetElements[i]),
					this.homepageSettings,
				);
				updatedWidgets[i].layout = widgetLayout;
			}

			const bannerElements = homepage
				.prev()
				.find(".widget")
				.not(".placeholder");
			for (let i = 0; i < bannerElements.length; i++) {
				updatedWidgets.push(CoreUtil.copy(this.bannerWidgets[i]));
			}
		}

		PageUtil.destroyHomepageControl(homepage);
		this.editModeService.stop({ isSave: isSave, result: updatedWidgets });
		this.pageEditActive = false;
	}

	private savePageData(pageData: IPageData): Observable<IPageDataResponse> {
		return this.pageService.updateSettings(pageData);
	}

	private isBannerMaxCount(): boolean {
		return this.bannerWidgets.length === BANNER_MAX_COUNT;
	}
}
