import {
	Component,
	Injector,
	NgModuleRef,
	OnInit,
	ViewChild,
	ViewContainerRef,
	isStandalone,
} from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import {
	ArrayUtil,
	CommonUtil,
	DialogButtonType,
	IApplication,
	IDialog,
	ILanguage,
	IValueItem,
	IWidgetContext,
	IWidgetInstance,
	IWidgetSettingMetadata,
	IWidgetSettingsComponent,
	IWidgetSettingsContext,
	IWidgetSettingsInstance,
	NumUtil,
	WidgetSettingsType,
} from "lime";
import {
	Constants,
	CoreBase,
	IWidget,
	IWidgetSettingMetadataEx,
	LanguageService,
	LazyTypeService,
	SettingItemType,
	WidgetService,
	WidgetSettingsContext,
	WidgetSettingsParameter,
	WidgetUtil,
} from "lime/core";

@Component({
	selector: "lm-widget-settings",
	templateUrl: "./widget-settings.html",
	styleUrls: ["./widget-settings.scss"],
})
export class WidgetSettingsComponent extends CoreBase implements OnInit {
	dialog: SohoModalDialogRef<WidgetSettingsComponent>;
	parameter: WidgetSettingsParameter;
	isSaveEnabled;
	isPublished: boolean;
	settings: IWidgetSettingMetadataEx[];
	lang: ILanguageLime;
	isEditMode: boolean;
	widgetTitleMaxLength: number;
	isTitleLocked: boolean;
	isCatalogTitle = false;

	private readonly webWidgetId: string;
	private widget: IWidget;
	private originalTitle: string;

	constructor(languageService: LanguageService) {
		super("WidgetSettingsComponent");
		this.lang = languageService.getLanguage();
		this.webWidgetId = Constants.mingleWebWidgetID;
	}

	ngOnInit(): void {
		const parameter = this.parameter;
		if (!parameter) {
			return;
		}

		const widget = parameter.widget;
		const definition = widget.definition;
		const lang = definition.lang;
		const isEdit = parameter.isEditMode;
		this.isEditMode = isEdit;
		this.isPublished =
			definition.isPublished || widget.parentContext.isPublished;

		// ReSharper disable once RedundantComparisonWithBoolean
		const widgetTitleLocked = widget.data.isTitleLocked === true;

		// Create settings objects used by the HTML template
		const values = widget.data.settings;
		let settings: IWidgetSettingMetadataEx[] = [];
		const metadata = widget.context.getSettings().getMetadata();
		if (metadata) {
			settings = WidgetUtil.getSettingsFromMetadata(metadata, values, lang);
		}

		// Add the application selector if necessary for private widgets or published widgets in edit mode
		// Unless explicity turned off by setting enableApplicationSelector to false in the manifest
		if (isEdit || !definition.isPublished) {
			const enableApplicationSelector =
				definition.enableApplicationSelector !== false;
			if (enableApplicationSelector) {
				const setting = this.createSelector(widget);
				if (setting) {
					settings.unshift(setting);
				}
			} else {
				this.logInfo(
					`Application selector is turned off in manifest for widget with id ${widget.id}`,
				);
			}
		}

		const isTitleEditDisabled =
			definition && definition.enableTitleEditDef === false;
		const isTitleEdit = widget.isTitleEditEnabled !== false;
		if (isTitleEdit || (isEdit && !isTitleEditDisabled)) {
			// If disabled from manifest then it should never be changable
			const title = widget.title;
			this.originalTitle = title;
			settings.unshift({
				type: SettingItemType.typeString,
				id: CommonUtil.random(),
				name: Constants.settingsNameWidgetTitle,
				value: title,
				definition: {} as IWidgetSettingMetadata,
				label: this.lang.title,
			} as IWidgetSettingMetadataEx);
			this.isCatalogTitle = widget.isCatalogTitle();
		}

		this.isTitleLocked = widgetTitleLocked || this.isCatalogTitle;

		let firstVisible: IWidgetSettingMetadataEx = null;
		// Calculate some values and set defaults if missing
		for (const setting of settings) {
			const metadata = setting.definition;
			if (!setting.type) {
				setting.type = WidgetSettingsType.stringType;
			}
			setting.isHidden =
				metadata.isHidden || (!isEdit && metadata.isVisible === false);
			setting.isReadOnly = !isEdit && metadata.isEnabled === false;
			setting.isVisible = WidgetUtil.isSettingsVisible(
				setting,
				this.isPublished,
				this.isEditMode,
			);
			if (firstVisible === null && setting.isVisible) {
				firstVisible = setting;
				setting.isFirst = true;
			} else {
				setting.isFirst = false;
			}

			if (setting.type === WidgetSettingsType.numberType) {
				const value = setting.value;
				if (value === null || value === "" || isNaN(value)) {
					setting.value = undefined;
				} else {
					setting.value = NumUtil.format(value);
				}
			}
		}

		// Everything is unlocked in edit mode for now.
		this.isSaveEnabled =
			isEdit ||
			isTitleEdit ||
			ArrayUtil.find(settings, (item: IWidgetSettingMetadataEx) => {
				const def = item.definition;
				return def.isVisible && def.isEnabled;
			});

		this.widget = widget;
		this.settings = settings;
		this.widgetTitleMaxLength = Constants.widgetTitleLength;
	}

	onClickIsLocked() {
		const isLocked = this.isTitleLocked;
		this.isTitleLocked = !isLocked;

		const metadata = this.settings[0] as IWidgetSettingMetadataEx;
		if (metadata.name === Constants.settingsNameWidgetTitle) {
			// Change the setting value for title if the title was locked and reset the title to the default widget title
			if (this.isTitleLocked) {
				metadata.value = this.widget.calculateTitle(true);
			}
		}
	}

	getPendoId(setting: IWidgetSettingMetadata): string {
		try {
			const id = this.widget.definition.standardWidgetId || this.widget.id;
			const idElement = id.replace(new RegExp("\\.", "gm"), "-");
			const nameElement = setting.name.replace(new RegExp("\\.", "gm"), "-");
			const pendoId = idElement + "-" + nameElement;
			return pendoId;
		} catch (ex) {
			this.logError("Failed to get pendo id", ex);
			return "item";
		}
	}

	getAutoId(setting: IWidgetSettingMetadata): string {
		return "lm-ws-" + this.getPendoId(setting);
	}

	onSave() {
		if (
			(this.isEditMode || this.widget.isTitleEditEnabled) &&
			this.settings[0].value === this.originalTitle
		) {
			// If title edit is enabled but the title is unchanged, remove that setting to prevent setting it locally.
			this.settings.shift();
		}

		// Update settings
		WidgetUtil.updateSettingsValues(
			this.settings,
			this.isTitleLocked,
			this.widget,
		);

		// Close dialog
		this.dialog.close({ value: this.widget });
	}

	onCancel() {
		this.dialog.close({ button: DialogButtonType.Cancel });
	}

	getAttributeValue(setting: IWidgetSettingMetadataEx): string {
		return setting.definition.isMandatory ? "required" : null;
	}

	isWebWidgetUrlSetting(setting): boolean {
		return this.widget.id === this.webWidgetId && setting.name === "url";
	}

	private createSelector(widget: IWidget): IWidgetSettingMetadataEx {
		// Show application instance selector if there are more than one instance
		const context = widget.context;
		const applications = context.getApplications();
		if (applications && applications.length != 0) {
			if (applications.length === 1) {
				this.logDebug(
					"There is only one application instance, the application selector will not be added to the settings UI.",
				);
				return null;
			}
		} else {
			return null;
		}

		const currentLogicalId = widget.data.logicalId || "";
		const defaultApp = this.getDefaultApplication(
			applications,
			WidgetUtil.getPrefferedLogicalIdInstance(widget.definition),
		);

		// Adding default first since that was the existing implementation, but fixed so that it is truly the default
		const values: IValueItem[] = [];
		let selectedItem = null;
		const defaultText =
			this.lang.defaultSelection + " (" + defaultApp.logicalId + ")";
		const defaultItem = { text: defaultText, value: "" };
		values.push(defaultItem);
		for (const application of applications) {
			const value = application.logicalId;
			const text = application.productName + " (" + value + ")";
			const item = { text: text, value: value };
			values.push(item);
			if (currentLogicalId === value) {
				selectedItem = item;
			}
		}

		if (selectedItem == null) {
			selectedItem = ArrayUtil.find(
				values,
				(item: IValueItem) => item.value === defaultApp.logicalId,
			);
		}

		const setting: IWidgetSettingMetadataEx = {
			type: "selector",
			id: CommonUtil.random(),
			name: Constants.settingsNameLogicalId,
			value: selectedItem,
			values: values,
			definition: {} as IWidgetSettingMetadata,
			label: this.lang.application,
		};
		return setting;
	}

	private getDefaultApplication(
		applications: IApplication[],
		prefferedInstanceId: string,
	): IApplication {
		if (!applications) {
			return null;
		}
		if (applications.length === 1) {
			return applications[0];
		}
		for (const application of applications) {
			if (prefferedInstanceId === application.logicalId) {
				return application;
			}
		}
		return applications[0];
	}
}

@Component({
	selector: "lm-custom-widget-settings",
	template: ` <div>
		<div #content class="lm-widget-settings-content"></div>
		<div class="modal-buttonset" id="lm-ws-custom-buttons">
			<button class="btn-modal" id="lm-ws-custom-cancel" (click)="cancel()">
				{{ lang.cancel }}
			</button>
			<button
				class="btn-modal-primary"
				id="lm-ws-custom-ok"
				(click)="save()"
				[disabled]="!isSaveEnabled">
				{{ lang.save }}
			</button>
		</div>
	</div>`,
})
export class CustomWidgetSettingsComponent extends CoreBase implements OnInit {
	parameter: WidgetSettingsParameter;
	dialog: SohoModalDialogRef<CustomWidgetSettingsComponent>;
	@ViewChild("content", { read: ViewContainerRef, static: true })
	content: ViewContainerRef;
	lang = {} as ILanguage;

	private widget: IWidget;
	private settings: any[];
	private settingsInstance = null as IWidgetSettingsInstance;
	private settingsContext: IWidgetSettingsContext;

	constructor(
		languageService: LanguageService,
		private readonly lazyTypeService: LazyTypeService,
		private readonly widgetService: WidgetService,
		private injector: Injector,
	) {
		super("CustomWidgetSettingsComponent");
		this.lang = languageService.getLanguage();
	}

	ngOnInit() {
		try {
			const parameter = this.parameter;
			const widget = parameter.widget;
			const context = new WidgetSettingsContext(
				widget,
				$(this.content.element.nativeElement),
				this.dialog as any as IDialog,
			);
			const settingsInstance = parameter.widgetSettingsFactory(
				context as any as IWidgetSettingsContext,
			);

			this.widget = widget;
			this.settingsInstance = settingsInstance;
			this.settingsContext = context;

			if (settingsInstance.angularConfig) {
				this.addContent(
					widget,
					context,
					settingsInstance as any as IWidgetSettingsInstance,
				);
			}
		} catch (e) {
			this.logError("Failed to create custom settings with factory ", e);
		}
	}

	save() {
		this.beforeClosing(true);
		this.dialog.close({ value: this.widget });
	}

	cancel() {
		this.beforeClosing(false);
		this.dialog.close();
	}

	get isSaveEnabled(): boolean {
		return this.settingsContext.isSaveEnabled();
	}

	private addContent(
		widget: IWidget,
		context: IWidgetSettingsContext,
		instance: IWidgetSettingsInstance,
	): void {
		const config = instance.angularConfig;

		const injector = Injector.create({
			providers: [
				{ provide: IWidgetSettingsContext, useValue: context },
				{ provide: IWidgetSettingsInstance, useValue: instance },
				{ provide: IWidgetContext, useValue: widget.context },
				{ provide: IWidgetInstance, useValue: widget.instance },
			],
			parent: widget.componentRef?.injector || this.injector,
		});
		let ngModuleRef: NgModuleRef<unknown>;
		if (!isStandalone(config.componentType)) {
			ngModuleRef = widget.definition.getModuleRef?.();
			if (!ngModuleRef) {
				this.logDebug(
					`No ngModuleRef from definition. Trying to get it from the injector.`,
				);
				ngModuleRef = widget.componentRef?.injector.get(NgModuleRef);
				if (!ngModuleRef) {
					this.logWarning(
						`Unable to get ngModuleRef. Injection might not work as expected!`,
					);
				}
			}
		}
		const componentRef = this.content.createComponent(config.componentType, {
			injector,
			ngModuleRef,
		});
		const component = componentRef.instance as IWidgetSettingsComponent;
		component.widgetSettingsContext = context;
		component.widgetSettingsInstance = instance;
	}

	private beforeClosing(isSave: boolean) {
		try {
			const instance = this.settingsInstance;
			if (instance && instance.closing) {
				instance.closing({ isSave: isSave });
			}
		} catch (e) {
			this.logError("Exception in settingsInstance.closing", e);
		}
	}
}
