import { Injectable } from "@angular/core";
import { SohoBusyIndicatorDirective } from "ids-enterprise-ng";
import { ArrayUtil } from "lime";
import {
	Constants,
	ContextService,
	CoreBase,
	DataService,
	ICatalogStartRequest,
	ICatalogStartResponse,
	IOrderBy,
	IPage,
	IWidgetCatalogRequest,
	IWidgetDetailInfoResponse,
	IWidgetHandle,
	IWidgetInfo,
	IWidgetListResponse,
	LanguageService,
	WidgetCategory,
	WidgetService,
} from "lime/core";
import { AsyncSubject, Observable } from "rxjs";

export interface ICatalogFilter {
	type?: CatalogContentType;
	owner?: string;
	query?: string;
	category?: number;
	orderBy?: IOrderBy;
	application?: { name: string; logicalIdPrefix: string };
	cloudSuite?: { key: string; value: string };
	tags?: string[];
}

export interface ICatalogSessionFilter {
	filter: ICatalogFilter;
	userFilter?: string;
	userModel?: any;
}

export enum CatalogContentType {
	All = 0,
	Published = 1,
	Standard = 2,
}

export interface ICatalogUser {
	name?: string;
	id?: string;
}

export interface IUserFilter {
	name: string;
	filter: ICatalogFilter;
	ownerDisplayName?: string;
}

export interface ICatalogCategory {
	id: string;
	name: string;
	fullName?: string;
	category: number;
	color: string;
}

export interface IPageCatalogItem extends IPage {
	id?: string;
	owner?: string;
	isStandardPage?: boolean;
	isDynamic?: boolean;
}

export interface IWidgetCatalogItem extends IWidgetInfo {
	id?: string;
	widgetHandle?: IWidgetHandle;
	canDuplicate?: boolean;
}

@Injectable({
	providedIn: "root",
})
export class CatalogDataService {
	private readonly lang: ILanguageLime;

	constructor(
		private readonly dataService: DataService,
		private readonly contextService: ContextService,
		languageService: LanguageService,
		private widgetService: WidgetService,
	) {
		this.lang = languageService.getLanguage();
	}

	startWidgetCatalog(isBanner = false): Observable<ICatalogStartResponse> {
		const request: ICatalogStartRequest = {
			recent: isBanner
				? this.contextService.getContext().settings.getRecentHeroWidgets()
				: this.contextService.getContext().settings.getRecentWidgets(),
			isBanner: isBanner,
		};
		return this.dataService.post("/widget/catalog/start", request);
	}

	getWidgetCatalogDetail(
		widgetHandle: IWidgetHandle,
	): Observable<IWidgetDetailInfoResponse> {
		return this.dataService.post("/widget/catalog/detail", {
			content: widgetHandle,
		});
	}

	listWidgets(request: IWidgetCatalogRequest): Observable<IWidgetListResponse> {
		const subject = new AsyncSubject<IWidgetListResponse>();

		if (!request.pageSize) {
			request.pageSize = 20;
		}
		this.dataService.post("/widget/list", request).subscribe(
			(response: IWidgetListResponse) => {
				subject.next(response);
				subject.complete();
			},
			(response: IWidgetListResponse) => {
				this.widgetService.invalidateWidgetDefinitions();
				subject.error(response);
			},
		);

		return subject.asObservable();
	}
}

@Injectable({
	providedIn: "root",
})
export class CatalogService extends CoreBase {
	private busyIndicator: SohoBusyIndicatorDirective;
	private lang: ILanguageLime;
	private categories: ICatalogCategory[];
	private _isBusy: boolean;

	constructor(languageService: LanguageService) {
		super("CatalogService");
		this.lang = languageService.getLanguage();
	}

	updateCategories(isWidget: boolean): ICatalogCategory[] {
		const lang = this.lang;
		let categories: ICatalogCategory[];

		if (isWidget) {
			categories = [
				{
					id: "lm-cat-ctg-all",
					name: lang.categoryAll,
					fullName: lang.allWidgets,
					category: WidgetCategory.All,
					color: "#50535A",
				},
				{
					id: "lm-cat-ctg-app",
					name: lang.categoryApplication,
					category: WidgetCategory.Application,
					color: "#488421",
				},
				{
					id: "lm-cat-ctg-bi",
					name: lang.categoryBI,
					category: WidgetCategory.BusinessIntelligence,
					color: "#2578A9",
				},
				{
					id: "lm-cat-ctg-proc",
					name: lang.categoryProcess,
					category: WidgetCategory.BusinessProcess,
					color: "#1D5F8A",
				},
				{
					id: "lm-cat-ctg-stat",
					name: lang.categoryStatistics,
					category: WidgetCategory.StatisticsUsage,
					color: "#6E5282",
				},
				{
					id: "lm-cat-ctg-soc",
					name: lang.categorySocial,
					category: WidgetCategory.Social,
					color: "#317C73",
				},
				{
					id: "lm-cat-ctg-util",
					name: lang.categoryUtilities,
					category: WidgetCategory.Utilities,
					color: "#A13030",
				},
				{
					id: "lm-cat-ctg-new",
					name: lang.categoryNewUpdated,
					category: WidgetCategory.NewUpdated,
					color: "#50535A",
				},
				{
					id: "lm-cat-ctg-my",
					name: lang.categoryMyRecent,
					category: WidgetCategory.MyRecent,
					color: "#50535A",
				},
			];
		} else {
			categories = [
				{
					id: "lm-cat-ctg-all",
					name: lang.categoryAll,
					fullName: lang.allPages,
					category: WidgetCategory.All,
					color: "#50535A",
				},
				{
					id: "lm-cat-ctg-new",
					name: lang.categoryNewUpdated,
					category: WidgetCategory.NewUpdated,
					color: "#50535A",
				},
			];
		}

		this.categories = categories;
		return categories;
	}

	/**
	 * Sets a busyindicator for use via the service.
	 * @param busyIndicator
	 */
	setBusyIndicator(busyIndicator: SohoBusyIndicatorDirective): void {
		this.busyIndicator = busyIndicator;
	}

	isBusy(): boolean {
		return this._isBusy;
	}

	/**
	 * Set the catalog in a busy or non-busy state.
	 * @param isBusy
	 */
	setBusy(isBusy: boolean): void {
		this._isBusy = isBusy;
		if (this.busyIndicator && this.busyIndicator.activated !== isBusy) {
			this.busyIndicator.activated = isBusy;
		}
	}

	getWidgetCategoryColor(category: number): string {
		const item = ArrayUtil.itemByProperty<ICatalogCategory>(
			this.categories,
			"category",
			category,
		);
		return item ? item.color : Constants.defaultColor;
	}

	getLocalizedCategoryName(category: number): string {
		const item = ArrayUtil.itemByProperty<ICatalogCategory>(
			this.categories,
			"category",
			category,
		);
		return item ? item.fullName || item.name : "";
	}
}
