import {
	Component,
	EventEmitter,
	Input,
	OnChanges,
	OnInit,
	Output,
	SimpleChanges,
	ViewChild,
} from "@angular/core";
import {
	SohoMessageService,
	SohoModalDialogService,
	SohoToastService,
	SohoToolbarComponent,
} from "ids-enterprise-ng";
import { ArrayUtil, HtmlUtil, StringUtil } from "lime";
import {
	AccessState,
	CommonDataService,
	ContainerService,
	ContextService,
	CoreBase,
	CoreUtil,
	EntityListType,
	EntityType,
	IApplicationInfo,
	IBadgePopoverInfo,
	ICatalogOptions,
	IContext,
	IEntityListItem,
	ILanguageInfo,
	IOperationResponse,
	IPage,
	IServerSettings,
	IWidgetDefinition,
	IWidgetDetailInfo,
	IWidgetDetailInfoResponse,
	IWidgetHandle,
	IWidgetInfo,
	LanguageService,
	PageService,
	ShowWidgetOrPagePermissionsComponent,
	UIUtil,
	WidgetAccessLevel,
	WidgetService,
	WidgetUtil,
} from "lime/core";
import {
	CatalogDataService,
	CatalogService,
	IPageCatalogItem,
	IWidgetCatalogItem,
} from "../catalog-core";

interface IDetailViewInfo {
	id: string;
	title: string;
	description: string;
	category?: string;
	widgetHandle?: string;
	displayIcon?: string;
	owner?: string;
	ownerName?: string;
	changeDate?: string;
	changedBy?: string; // Pages only
	version?: string;
	basedOn?: { title: string; widgetId: string };
	application?: IApplicationInfo;
	tags?: string;
	languages?: ILanguageInfo[];
	colorStyle: any;
	item?: IWidgetInfo;
	usedBy?: number; // Pages only
	languagesTranslated?: string;
	isLocalized?: boolean;
	isStandardPage?: boolean;
	author: string;
	screenshots?: string[];
	badges?: IBadgePopoverInfo[]; // Should this be here?
}

/**
 * Catalog Detail Component
 */
@Component({
	selector: "lm-catalog-detail-component",
	templateUrl: "./catalog-detail.html",
	styleUrls: ["./catalog-detail.scss"],
})
export class CatalogDetailComponent
	extends CoreBase
	implements OnInit, OnChanges
{
	private get page(): IPageCatalogItem {
		return this.detailItem as IPageCatalogItem;
	}

	private get widget(): IWidgetCatalogItem {
		return this.detailItem as IWidgetCatalogItem;
	}

	private get settings(): IServerSettings {
		return this.context.settings;
	}

	private get isPublished(): boolean {
		return this.isWidget ? this.isPublishedWidget : this.isPublishedPage;
	}

	private get isPublishEnabled(): boolean {
		return this.isWidget
			? this.settings.isWidgetPublishEnabled()
			: this.settings.isPagePublishEnabled();
	}

	private get isPublishedPage(): boolean {
		const item = this.page;
		return !!(item && !item.isStandardPage && item.owner);
	}

	private get isPublishedWidget(): boolean {
		const item = this.widget;
		return item && !!item.standardWidgetId;
	}

	private get isDynamic(): boolean {
		return this.isWidget ? false : this.page.isDynamic;
	}

	@ViewChild(SohoToolbarComponent, { static: false })
	sohoToolbar: SohoToolbarComponent;

	@Input() detailItem: any; // TODO This object should be typed
	@Output() detailItemChange = new EventEmitter<any>();

	@Input() isWidget: boolean;
	@Input() canPreview: boolean;
	@Input() canAddItem: boolean;
	@Input() headerColor: string;
	@Input() featuredItems: any[];
	@Input() maxFeatured: number;
	@Input() isBannerMode: boolean;
	@Input() categoryTitle: string;
	@Input() applications: IApplicationInfo[];
	@Input() options: ICatalogOptions;

	@Output() onClickAdd = new EventEmitter<any>();
	@Output() onClickPreview = new EventEmitter<any>();
	@Output() onDeleted = new EventEmitter<string>();
	@Output() onClickAddTag = new EventEmitter<string>();
	@Output() onClickEdit = new EventEmitter<any>();

	lang: ILanguageLime;
	isError = false;
	isContentAdmin = false;
	isSupportUser = false;
	isFeatured = false;
	isBusy = false;
	canEditPublished = false;
	canDuplicate = true;
	canViewPermissions = false;
	isSetFeaturedEnabled = false;
	isAvailableLanguagesEnabled = false;

	private readonly context: IContext;
	private isBasedOnItemView = false;
	private previousDetailItem: IDetailViewInfo;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		contextService: ContextService,
		private readonly commonDataService: CommonDataService,
		private readonly toastService: SohoToastService,
		private readonly widgetService: WidgetService,
		private readonly pageService: PageService,
		private readonly containerService: ContainerService,
		private readonly catalogDataService: CatalogDataService,
		private readonly catalogService: CatalogService,
		private readonly sohoModalDialogService: SohoModalDialogService,
	) {
		super("CatalogDetailComponent", messageService, languageService);
		this.lang = languageService.getLanguage();
		const context = contextService.getContext();
		this.isContentAdmin = context.isPageAdministrator;
		this.isSupportUser = context.isContentSupportUserOnly;
		this.isSetFeaturedEnabled = this.isContentAdmin;
		this.context = context;
	}

	ngOnInit(): void {
		if (this.options.isSelect) {
			// Disable functionality not allowed in select mode
			this.isContentAdmin = false;
			this.isSupportUser = false;
			this.isSetFeaturedEnabled = false;
			this.canDuplicate = false;
		}

		if (this.isWidget) {
			const widget = this.widget;
			this.openWidgetDetail(widget.widgetId, widget.standardWidgetId);
		} else {
			this.openPageDetail(this.page);
		}

		setTimeout(() => {
			this.sohoToolbar.updated();
		}, 0);
	}

	ngOnChanges(changes: SimpleChanges): void {
		const item = changes.detailItem;
		const isChanged =
			item &&
			item.previousValue &&
			item.currentValue &&
			item.currentValue !== item.previousValue;
		if (!isChanged) {
			return;
		}

		if (this.isWidget) {
			const widget = item.currentValue as IWidgetCatalogItem;
			this.openWidgetDetail(widget.widgetId, widget.standardWidgetId);
			return;
		}

		this.openPageDetail(item.currentValue as IPageCatalogItem);
	}

	onClickDelete() {
		if (this.isWidget) {
			this.deleteWidget();
			return;
		}

		this.deletePage();
	}

	onClickOpenBasedOn() {
		const item = this.detailItem as IDetailViewInfo;
		this.isBasedOnItemView = true;
		this.previousDetailItem = Object.assign({}, item);
		this.openWidgetDetail(item.basedOn.widgetId, null);
	}

	onClickFeature() {
		const item = this.detailItem.item;
		if (item) {
			const id = this.isWidget ? item.widgetId : item.data.id;
			const entityItem: IEntityListItem = {
				listType: EntityListType.Featured,
				entityType: this.isWidget
					? this.isBannerMode
						? EntityType.HeroWidget
						: EntityType.Widget
					: EntityType.Page,
				entity: id,
			};

			if (this.isWidget) {
				const widgetInfo = item as IWidgetInfo;
				const standardId = widgetInfo.standardWidgetId;
				if (standardId) {
					entityItem.relatedEntity = standardId;
				}
			}

			const existing = this.isWidget
				? ArrayUtil.itemByProperty(this.featuredItems, "widgetId", id)
				: ArrayUtil.itemByProperty(this.featuredItems, "id", id);
			if (existing) {
				this.commonDataService.removeEntityListItem(entityItem).subscribe(
					() => {
						this.isFeatured = false;
						ArrayUtil.remove(this.featuredItems, existing);
						this.showToast(
							this.lang.unsetFeatured,
							this.lang.messageUnsetFeatured,
						);
					},
					(response: IOperationResponse) => {
						this.logError(
							`Couldn't remove item with id ${id} from featured items`,
							response,
						);
						this.showError(this.lang.unsetFeatured, this.lang.errorGeneric);
						this.setIsFeatured();
					},
				);
			} else {
				this.commonDataService.addEntityListItem(entityItem).subscribe(
					() => {
						item.featuredClass = this.isWidget
							? this.widgetService.getFeaturedBackgroundClass(item.category)
							: this.pageService.getFeaturedBackgroundClass(item.data.color);
						this.isFeatured = true;
						this.featuredItems.unshift(item);
						if (this.featuredItems.length > this.maxFeatured) {
							this.featuredItems.pop();
						}
						this.showToast(this.lang.setFeatured, this.lang.messageSetFeatured);
					},
					(response) => {
						this.logError(
							`Couldn't add item with id ${id} to featured items`,
							response,
						);
						this.showError(this.lang.setFeatured, this.lang.errorGeneric);
						this.setIsFeatured();
					},
				);
			}
		}
	}

	onClickCloseDetails() {
		if (this.isBasedOnItemView) {
			this.detailItem = this.previousDetailItem;
			this.isBasedOnItemView = false;
			this.initEdit();
			this.setIsFeatured();
			this.updateLanguages();
		} else {
			this.detailItemChange.emit(null);
		}
	}

	showPermissions() {
		const dialog = this.sohoModalDialogService
			.modal(
				ShowWidgetOrPagePermissionsComponent,
				this.containerService.dialogParent,
			)
			.id("lm-prm-mdl")
			.title(this.lang.permissions);

		const item = this.detailItem;

		const self = this;
		dialog
			.apply((component) => {
				component.dialog = dialog;
				component.userId = self.context.getUserId();
				if (self.isWidget) {
					component.widgetHandle = item.widgetHandle;
				} else {
					component.id = item.id;
				}
			})
			.open();
	}

	onClickTag(tag: string) {
		this.onClickCloseDetails();
		this.onClickAddTag.emit(tag);
	}

	private initEdit(): void {
		if (this.options.isSelect || this.isDynamic) {
			return;
		}

		this.canEditPublished = false;
		this.canViewPermissions = false;

		if (this.isPublished) {
			if (this.isPublishEnabled) {
				const item = this.detailItem;
				this.canEditPublished =
					this.isContentAdmin || this.isOwner(item) || item.isEditable;
				this.canViewPermissions = this.canEditPublished || this.isSupportUser;
			} else {
				this.canViewPermissions = this.isContentAdmin || this.isSupportUser;
			}
			return;
		}

		this.canViewPermissions = this.isContentAdmin || this.isSupportUser;
	}

	private deleteWidget(): void {
		const item = this.widget;
		const id = item.id;

		// Show delete widget confirmation dialog.
		const buttons = [
			{
				text: this.lang.no,
				id: "lm-cat-deletewidget-message-no",
				click: (e, modal) => {
					modal.close(true);
				},
			},
			{
				text: this.lang.yes,
				id: "lm-cat-deletewidget-message-yes",
				click: (e, modal) => {
					modal.close(true);
					this.setBusy(true);
					// Delete widget
					this.widgetService.deletePublished([item.widgetHandle]).subscribe(
						(response) => {
							this.onDeleteResponse(id);
							this.showToast(
								this.lang.deleteWidget,
								this.lang.format(this.lang.widgetDeleted, item.title),
							);
							this.setBusy(false);
						},
						(r: IOperationResponse) => {
							this.widgetService.handleError(r);
							this.setBusy(false);
						},
					);
				},
				isDefault: true,
			},
		];

		this.messageService
			.message()
			.title(this.lang.deleteWidget)
			.message(
				this.lang.format(
					this.lang.confirmDeleteCustomWidget,
					HtmlUtil.escapeStringForHtml(item.title),
				),
			)
			.buttons(buttons)
			.attributes({ name: "id", value: "lm-cat-deletewidget-message" })
			.open();

		return;
	}

	private deletePage(): void {
		const page = this.page;
		const id = page.id;
		const title = page.title;

		this.containerService
			.getContainer()
			.delete(id, title, true)
			.subscribe(
				(response) => {
					this.onDeleteResponse(id);
					this.showToast(
						this.lang.deletePage,
						this.lang.format(this.lang.pageDeleted, title),
					);
				},
				(r: IOperationResponse) => {
					this.pageService.handleError(r);
				},
			);
	}

	private hasLanguages(): boolean {
		const isTranslationEnabled = this.settings.isContentTranslationEnabled();
		const item = this.detailItem;
		if (!item) {
			return false;
		}
		const isPublished = CoreUtil.isGuid(item.id);

		if (isPublished && !isTranslationEnabled) {
			// Don't show translations for published content if translations are turned off
			return false;
		}
		return (
			(item.isLocalized || this.isWidget) &&
			item.languages &&
			item.languages.length > 0
		);
	}

	private updateLanguages(): void {
		this.isAvailableLanguagesEnabled = this.hasLanguages();
	}

	private isOwner(item): boolean {
		const isPublished = this.isWidget
			? !!item.standardWidgetId
			: !item.isStandardPage && item.owner;
		if (!isPublished) {
			// Standard items have no owner
			return false;
		}
		// Note a widget with can publish has same rights som the owner
		return this.context.isCurrentUser(item.owner);
	}

	private findApplication(prefix: string): IApplicationInfo {
		if (!prefix) {
			return null;
		}

		let item: IApplicationInfo = null;
		while (!StringUtil.isNullOrWhitespace(prefix)) {
			item = ArrayUtil.itemByProperty(
				this.applications,
				"logicalIdPrefix",
				prefix,
			);
			if (item) {
				break;
			}
			prefix = prefix.substring(0, prefix.lastIndexOf("."));
		}
		return item;
	}

	private onDeleteResponse(id: string) {
		this.onDeleted.emit(id);
		this.onClickCloseDetails();
	}

	private openWidgetDetail(id: string, pid: string) {
		this.setBusy(true);

		this.canDuplicate = !!pid; // Standard widgets can never be duplicated
		const widgetHandle = this.createWidgetHandle(id, pid);
		this.catalogDataService.getWidgetCatalogDetail(widgetHandle).subscribe(
			(response: IWidgetDetailInfoResponse) => {
				const widgetDetails = response.content;
				if (this.isValidWidgetDetails(widgetDetails)) {
					const item = this.createWidgetItem(widgetHandle, widgetDetails);
					this.detailItem = item;
					this.updateLanguages();
					this.setIsFeatured();
					this.initEdit();
					if (!item.canDuplicate) {
						this.canDuplicate = false;
					}
					this.isError = false;
				} else {
					this.isError = true;
				}

				this.setBusy(false);
			},
			(r: IOperationResponse) => {
				this.isError = true;
				this.setBusy(false);
			},
			() => {
				this.setBusy(false);
			},
		);
	}

	private isValidWidgetDetails(widgetDetails: IWidgetDetailInfo): boolean {
		return !!(
			widgetDetails &&
			widgetDetails.widgetDefinitionItem &&
			widgetDetails.widgetInfo
		);
	}

	private createWidgetItem(
		widgetHandle: IWidgetHandle,
		widgetDetails: IWidgetDetailInfo,
	): IWidgetCatalogItem {
		const widgetDefinitionItem = widgetDetails.widgetDefinitionItem;
		const definition = widgetDefinitionItem.definition;
		const isPublished = !!definition.standardWidgetId;

		const widgetInfo = widgetDetails.widgetInfo;
		widgetInfo.displayIcon = this.widgetService.createImagePath(widgetInfo);

		let author: string;
		if (!isPublished && definition && definition.author) {
			author = HtmlUtil.escapeStringForHtml(definition.author);
		}

		const item = {
			author: author,
			id: widgetHandle.id,
			title: this.getWidgetTitle(widgetDetails),
			widgetHandle: widgetHandle,
			description: widgetInfo.description,
			owner: widgetInfo.owner,
			ownerName: isPublished
				? this.setOwnerName(widgetInfo.owner, widgetInfo.ownerName)
				: "",
			changeDate: widgetInfo.changeDate,
			changedBy: widgetInfo.changedByName,
			basedOn: isPublished
				? {
						title: widgetDefinitionItem.standardTitle,
						widgetId: definition.standardWidgetId,
				  }
				: null,
			displayIcon: widgetInfo.displayIcon,
			version: definition.displayVersion || definition.version,
			tags: definition.tags,
			application: this.findApplication(definition.applicationLogicalId),
			languages: widgetDetails.languages,
			languagesTranslated: this.getTranslatedLanguages(widgetDetails.languages),
			item: widgetInfo,
			isBannerEnabled: ArrayUtil.contains(definition.targets, "banner"),
			isBannerOnly: this.isBannerOnly(definition),
			hasRestrictions: widgetInfo.hasRestrictions,
			standardWidgetId: widgetInfo.standardWidgetId,
			isEditable: WidgetUtil.isEditable(widgetDefinitionItem.accessLevel),
			canDuplicate:
				widgetDefinitionItem.standardAccessLevel >= WidgetAccessLevel.Configure,
			screenshots: this.widgetService.createScreenshotPaths(definition),
			badges: WidgetUtil.getBadges(definition, this.lang),
		} as IWidgetCatalogItem;

		return item;
	}

	private getWidgetTitle(detailInfo: IWidgetDetailInfo): string {
		try {
			const widgetDef = detailInfo.widgetDefinitionItem;
			if (!StringUtil.isNullOrWhitespace(widgetDef.catalogTitle)) {
				return widgetDef.catalogTitle;
			}
			return detailInfo.widgetInfo.title;
		} catch (ex) {
			this.logError("Failed to get title", ex);
			return "";
		}
	}

	private isBannerOnly(widgetDefinition: IWidgetDefinition): boolean {
		if (widgetDefinition.target === "banner") {
			return true;
		}
		const targets = widgetDefinition.targets;
		if (targets && targets.length === 1 && targets[0] === "banner") {
			return true;
		}
		return false;
	}

	private openPageDetail(item: IPage) {
		this.setBusy(true);
		const data = item.data;
		const id = data.id;
		this.detailItem = {
			id: data.id,
			title: item.title || data.title,
			description: item.description || data.description,
			colorStyle: UIUtil.colorToBackgroundStyle(data.color),
			changeDate: data.changeDate,
			owner: data.ownerId,
			ownerName: data.ownerName,
			tags: data.tags,
			changedBy: data.changedByName,
			usedBy: item.popularity,
			item: item,
			isEditable: item.isEditable,
			isLocalized: item.isLocalized,
			isStandardPage: data.isStandard,
			isDynamic: data.isDynamic,
			hasRestrictions: item.accessState === AccessState.Restricted, // TODO: unknown 0, how to handle, and also is that for disabled but owner?
		};
		this.initEdit();
		this.setIsFeatured();

		this.canDuplicate =
			!data.isDynamic && this.settings.isPublicPageCopyEnabled();

		const isTranslationEnabled = this.settings.isContentTranslationEnabled();
		const loadLanguages =
			!CoreUtil.isGuid(this.detailItem.id) || isTranslationEnabled;
		if (loadLanguages && item.isLocalized) {
			this.pageService.getPageCatalogDetail(id).subscribe(
				(response: IWidgetDetailInfoResponse) => {
					if (!response.hasError() && response.content) {
						this.detailItem.languages = response.content.languages;
						this.detailItem.languagesTranslated = this.getTranslatedLanguages(
							response.content.languages,
						);
					} else {
						this.logError("Failed to get page detail", response);
					}
					this.updateLanguages();
				},
				(e) => {
					this.logError("Unable to get page detail, server returned error.", e);
					this.setBusy(false);
				},
				() => {
					this.setBusy(false);
				},
			);
		} else {
			this.isAvailableLanguagesEnabled = false;
			this.setBusy(false);
		}
	}

	private showToast(title: string, message: string): void {
		this.toastService.show(CoreUtil.getToastOptions(title, message));
	}

	/**
	 * Creates an object with two arrays containing translated language names and their codes.
	 * @param languages
	 */
	private getTranslatedLanguages(languages: ILanguageInfo[]): string {
		let translatedLanguages = "";

		if (languages) {
			// Translate languages and sort alphabetically
			languages.forEach((language) => {
				const langKey = `lang${language.tag.replace("-", "")}`;
				language.name = this.languageService.get(langKey);
			});
			languages = ArrayUtil.sortByProperty(languages, "name");

			// Create string
			languages.forEach((language: ILanguageInfo) => {
				translatedLanguages += language.name + ", ";
			});
			translatedLanguages = translatedLanguages.substr(
				0,
				translatedLanguages.length - 2,
			);
		}

		return translatedLanguages;
	}

	private setOwnerName(owner: string, ownerName: string): string {
		let returnVal = "";
		if (ownerName) {
			returnVal = ownerName;
		} else if (owner && owner.indexOf("@") > 0) {
			returnVal = owner;
		}
		return returnVal;
	}

	private setIsFeatured(): void {
		const detailItem = this.detailItem;
		if (detailItem && detailItem.item) {
			this.isFeatured = this.isWidget
				? ArrayUtil.containsByProperty(
						this.featuredItems,
						"widgetId",
						detailItem.item.widgetId,
				  )
				: ArrayUtil.containsByProperty(
						this.featuredItems,
						"id",
						detailItem.item.id,
				  );
		}
	}

	private createWidgetHandle(id: string, pid: string): IWidgetHandle {
		const widgetHandle: IWidgetHandle = { id: id, pid: pid };
		widgetHandle.byRef = !StringUtil.isNullOrWhitespace(pid);
		return widgetHandle;
	}

	private setBusy(isBusy: boolean): void {
		this.catalogService.setBusy(isBusy);
	}
}
