import {
	Component,
	EventEmitter,
	Input,
	OnChanges,
	Output,
	SimpleChange,
} from "@angular/core";
import { ArrayUtil } from "lime";
import { CoreBase, LanguageService } from "lime/core";
import { CatalogContentType, ICatalogFilter } from "../catalog-core";

@Component({
	selector: "lm-catalog-tags-accordion",
	templateUrl: "./catalog-tags-accordion.html",
	styleUrls: ["./catalog-tags-accordion.scss"],
})
export class CatalogTagsAccordionComponent
	extends CoreBase
	implements OnChanges
{
	@Input() filter: ICatalogFilter;
	@Input() isOpened: boolean;
	@Input() isWidget: boolean;
	@Input() isFilterActive: boolean;
	@Input() isMe: boolean;
	@Input() relatedTags: string[];
	@Input() catalogSearchQuery: string;
	@Input() ownerDisplayName: string;

	@Output() filterChanged: EventEmitter<null> = new EventEmitter();
	@Output() clearSearch: EventEmitter<Event> = new EventEmitter();

	lang: ILanguageLime;
	isRelatedTagsExpanded = false;

	constructor(languageService: LanguageService) {
		super("TagsAccordionComponent");
		this.lang = languageService.getLanguage();
	}

	ngOnChanges(changes: { [propKey: string]: SimpleChange }) {
		for (const propName in changes) {
			if (propName === "filter" || propName === "relatedTags") {
				if (this.relatedTags.length === 0 && this.isRelatedTagsExpanded) {
					this.isRelatedTagsExpanded = !this.isRelatedTagsExpanded;
				}
			}
		}
	}

	stopEventPropagation(event: Event): void {
		event.stopPropagation();
	}

	/**
	 * Clears all user selected filters.
	 */
	onClickClearAll(event: Event): void {
		event.stopImmediatePropagation();
		const filter = this.filter;
		filter.tags = [];
		filter.application = null;
		filter.cloudSuite = null;
		filter.owner = null;
		filter.type = CatalogContentType.All;
		if (filter.query) {
			// clearSearch will also trigger a onFilterChange
			this.clearSearch.emit(event);
		} else {
			this.onFilterChange();
		}
	}

	onFilterChange(): void {
		this.filterChanged.emit(null);
	}

	/**
	 * Removes a tag from filter.
	 */
	removeTag(tag: string): void {
		ArrayUtil.remove(this.filter.tags, tag);
		this.onFilterChange();
	}

	/**
	 * Add a tag to the filter.
	 */
	onAddTag(tag: string): void {
		if (
			!ArrayUtil.contains(this.filter.tags, tag) &&
			this.filter.tags.length < 5
		) {
			this.filter.tags.push(tag);
			this.onFilterChange();
		}
	}
}
