import { Component, Input } from "@angular/core";
import { fromEvent, Subscription } from "rxjs";
import { filter, share, tap } from "rxjs/operators";

@Component({
	selector: "lm-gallery",
	styleUrls: ["./gallery.scss"],
	templateUrl: "./gallery.html",
})
export class GalleryComponent {
	@Input() images: string[];
	isOpen: boolean;
	viewerIndex = 0;

	private keyboardListeners: Subscription[] = [];

	setupKeyboardListeners() {
		const keyUps$ = fromEvent<KeyboardEvent>(window, "keyup").pipe(share());
		const arrowLeft$ = keyUps$.pipe(
			filter(({ key }) => key === "ArrowLeft"),
			tap(() => this.previous()),
		);
		const arrowRight$ = keyUps$.pipe(
			filter(({ key }) => key === "ArrowRight"),
			tap(() => this.next()),
		);

		this.keyboardListeners = [arrowLeft$.subscribe(), arrowRight$.subscribe()];
	}

	teardownKeyboardListeners() {
		this.keyboardListeners.forEach((sub) => sub.unsubscribe());
	}

	open(index: number) {
		this.viewerIndex = index;
		this.isOpen = true;
		this.setupKeyboardListeners();
	}

	close() {
		this.isOpen = false;
		this.teardownKeyboardListeners();
	}

	next() {
		if (this.viewerIndex < this.images.length - 1) {
			this.viewerIndex += 1;
		}
	}

	previous() {
		if (this.viewerIndex > 0) {
			this.viewerIndex -= 1;
		}
	}
}
