/**
 * Abstract representation of the host of a Catalog.
 */
export interface ICatalogHost {
	close(result?: any): void;
	closed(handler: () => void): void;
	opened(handler: () => void): void;
}

@Injectable({
	providedIn: "root",
})
export class CatalogStartService
	extends CoreBase
	implements ICatalogStartService
{
	private readonly lang: ILanguageLime;
	private catalogHost: ICatalogHost;

	constructor(
		private readonly dataService: CatalogDataService,
		protected readonly languageService: LanguageService,
		private readonly capService: SohoContextualActionPanelService,
		private readonly progressService: ProgressService,
		dialogService: SohoModalDialogService,
	) {
		super("CatalogStartService");
		this.lang = languageService.getLanguage();
		this.progressService.setBusy(false);
	}

	/**
	 * Opens the widget catalog in a dialog window.
	 */
	openWidgetCatalog(
		options: ICatalogOptions,
		parentView: ViewContainerRef,
	): Observable<IDialogResult> {
		this.addWidgetOptions(options);
		return this.openCatalog(options, parentView);
	}

	createWidgetCatalog(
		options: ICatalogOptions,
		parentView: ViewContainerRef,
	): Observable<IDialogResult> {
		this.addWidgetOptions(options);

		const ref = parentView.createComponent(CatalogComponent);
		const instance = ref.instance;

		const host = new CustomCatalogHost();
		instance.options = options;
		instance.dialog = host;

		host.open();

		this.catalogHost = host;
		return host.closed$;
	}

	openPageCatalog(
		options: ICatalogOptions,
		parentView: ViewContainerRef,
	): void {
		// Page catalog does not use the observable
		this.openCatalog(options, parentView);
	}

	closeCatalog(): void {
		if (this.catalogHost) {
			this.catalogHost.close();
			this.catalogHost = null;
		}
	}

	private addWidgetOptions(options: ICatalogOptions): void {
		options.type = CatalogType.Widget;
		options.startProvider = () => {
			return this.dataService.startWidgetCatalog(options.isBanner);
		};
		options.provider = (r) => {
			return this.dataService.listWidgets(r);
		};
	}

	private openCatalog(
		options: ICatalogOptions,
		parentView: ViewContainerRef,
	): Observable<IDialogResult> {
		const subject = new AsyncSubject<IDialogResult>();

		this.progressService.setBusy(true);
		const panel = this.capService
			.contextualactionpanel(CatalogComponent, parentView)
			.initializeContent(false)
			.modalSettings({
				useFlexToolbar: true,
				showCloseBtn: false,
				id: "lm-cat-cap",
				trigger: "immediate",
			})
			.afterClose((result: object) => {
				this.catalogHost = null;
				options.addCallback = null;
				subject.next(result);
				subject.complete();
			});

		panel
			.apply((component) => {
				const host = new DialogCatalogHost(panel);
				this.catalogHost = host;
				component.dialog = host;
				component.options = options;
			})
			.open();

		return subject.asObservable();
	}
}

export class DialogCatalogHost {
	constructor(private panel: SohoContextualActionPanelRef<CatalogComponent>) {}

	close(result?: any): void {
		this.panel.close(result, true);
	}

	closed(handler: () => void): void {
		this.panel.closed(handler as any);
	}

	opened(handler: () => void): void {
		this.panel.opened(handler as any);
	}
}

export class CustomCatalogHost {
	private closeSubject = new ReplaySubject<IDialogResult>(1);

	closed$ = this.closeSubject.asObservable();

	private closedHandler: () => void;
	private openedHandler: () => void;

	open(): void {
		if (this.openedHandler) {
			this.openedHandler();
		}
	}

	close(result?: any): void {
		if (this.closedHandler) {
			this.closedHandler();
		}
		this.closeSubject.next(result);
	}

	closed(handler: () => void): void {
		this.closedHandler = handler;
	}

	opened(handler: () => void): void {
		this.openedHandler = handler;
	}
}

/**
 * Catalog Save Filter Component
 */
@Component({
	templateUrl: "./catalog-save-filter.html",
})
export class CatalogSaveFilterComponent
	extends ModalDialogBase
	implements OnInit
{
	userFilterName: string;
	lang: ILanguageLime;
	viewNameLength = 50;

	constructor(languageService: LanguageService) {
		super("CatalogSaveFilterComponent");
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		this.canClose = false;
		this.initModalDialog();
	}

	save(): void {
		const name = (this.userFilterName || "").trim();
		if (!name) {
			return;
		}

		this.closeWithResult(DialogButtonType.Ok, name);
	}
}

/**
 * Catalog Component
 */
@Component({
	templateUrl: "./catalog.html",
	styleUrls: ["./catalog.scss"],
})
export class CatalogComponent extends CoreBase implements OnDestroy, OnInit {
	@ViewChild(SohoBusyIndicatorDirective, { static: true })
	busyIndicator: SohoBusyIndicatorDirective;
	dialog: ICatalogHost;
	lang: ILanguageLime;
	context: IContext;
	options: ICatalogOptions;
	title: string;
	catalogMode: string;
	isBannerMode: boolean;
	isWidget: boolean;
	isPageAdmin: boolean;
	isWidgetPublishEnabled: boolean;
	isFeatureStandardPagesEnabled: boolean;
	isDev: boolean;
	tagsAutocompleteSource: Function;
	autocompleteTemplate: string;
	canAddItem: boolean;
	canPreview: boolean;
	isOpened = false;
	isFilterActive: boolean;

	activeItem: ICatalogItem;
	items: ICatalogItem[] = [];
	featuredItems: ICatalogItem[] = [];
	maxFeatured: number;
	newItems: ICatalogItem[] = [];
	recentItems: ICatalogItem[] = [];
	tags: string[] = [];
	relatedTags: string[] = [];

	userFilters: IUserFilter[] = [];
	orderByArray: IOrderBy[] = [];
	categories: ICatalogCategory[] = [];
	labelAdd: string;
	labelNoItems: string;
	labelFeatured: string;
	filter: ICatalogFilter = { tags: [] };
	applications: IApplicationInfo[] = [];
	cloudSuites: ICloudSuiteInfo[] = [];
	tagModel: string;
	catalogSearchQuery: string;
	currentUser: ICatalogUser;
	ownerSearchModel: { inputText?: string; value: ICatalogUser } = { value: {} };
	selectedFilterName: string;
	@ViewChild("listToolbar", { static: true }) listToolbar: any; // SohoToolbarComponent

	private recentItemsString: string;
	private isPublicPageAddEnabled: boolean;
	private isDuplicatePublishedPageEnabled: boolean;
	private isSearchActive: boolean;
	private homeLoaded: boolean;
	private paging: IPagingInfo;
	private hasMore: boolean;
	private timeout: number;
	private bannerWidgetCount: number;
	private isWidgetUpdated = false;

	constructor(
		messageService: SohoMessageService,
		languageService: LanguageService,
		private readonly contextService: ContextService,
		private readonly editModeService: EditModeService,
		private readonly widgetService: WidgetService,
		private readonly pageService: PageService,
		private readonly commonDataService: CommonDataService,
		private readonly dialogService: SohoModalDialogService,
		private readonly containerService: ContainerService,
		private readonly catalogService: CatalogService,
		private readonly progressService: ProgressService,
		private readonly devService: DevService,
		private readonly ngZone: NgZone,
	) {
		super("CatalogComponent", messageService, languageService);

		const lang = languageService.getLanguage();
		this.lang = lang;
		const context = this.contextService.getContext();
		const settings = context.settings;
		this.context = context;

		this.initAutocomplete();

		this.orderByArray = [
			{
				order: SortOrder.Ascending,
				entity: EntitySortBy.Title,
				name: lang.sortTitleAsc,
			},
			{
				order: SortOrder.Descending,
				entity: EntitySortBy.Title,
				name: lang.sortTitleDesc,
			},
			{
				order: SortOrder.Descending,
				entity: EntitySortBy.ChangeDate,
				name: lang.sortNewest,
			},
			{
				order: SortOrder.Ascending,
				entity: EntitySortBy.ChangeDate,
				name: lang.sortOldest,
			},
		];

		this.isPageAdmin = context.isPageAdministrator;
		this.isWidgetPublishEnabled = settings.isWidgetPublishEnabled();
		this.isPublicPageAddEnabled = settings.isPublicPageAddEnabled();
		this.isDuplicatePublishedPageEnabled = settings.isPublicPageCopyEnabled();
		this.isFeatureStandardPagesEnabled = settings.isFeatureStandardPages();

		this.currentUser = { id: context.getUserId() };
	}

	ngOnDestroy(): void {
		this.logDebug("ngOnDestroy");

		this.dialog = null;

		const options = this.options;
		if (options) {
			// DOM leaks without this reset
			options.addCallback = null;
			options.previewCallback = null;
			options.republishCallback = null;
			this.options = null;
		}

		this.catalogService.setBusyIndicator(null);
	}

	ngOnInit(): void {
		this.catalogService.setBusyIndicator(this.busyIndicator);
		if (this.options.type === CatalogType.Widget) {
			this.initWidgetMode();
		} else {
			this.initPageMode();
		}
		this.categories = this.catalogService.updateCategories(this.isWidget);

		if (!this.isDev) {
			this.setBusy(true);
		}

		const context = this.context;
		this.recentItemsString = this.isBannerMode
			? context.settings.getRecentHeroWidgets()
			: context.settings.getRecentWidgets();
		this.canAddItem =
			this.isWidget || this.isPageAdmin || this.isPublicPageAddEnabled;
		this.canPreview =
			!this.isWidget &&
			(this.isPageAdmin ||
				this.isPublicPageAddEnabled ||
				this.isDuplicatePublishedPageEnabled);

		this.initDialogEvents();
		this.loadFilters();
		this.initView();
		this.progressService.setBusy(false);
	}

	onListScroll(event: Event): void {
		if (!this.hasMore || this.filter.category === -3 || this.activeItem) {
			return;
		}

		const element = $(event.target as any) as JQuery;
		const scrollTop = element.scrollTop();
		if (scrollTop + element[0].offsetHeight + 150 >= element[0].scrollHeight) {
			let timeout = this.timeout;
			if (timeout) {
				window.clearTimeout(timeout);
				timeout = null;
			}
			this.timeout = window.setTimeout(() => {
				if (!this.isBusy()) {
					this.loadItems();
				}
				element.scrollTop(scrollTop);
			}, 100);
		}
	}

	onClickDetails(item: ICatalogItem): void {
		if (this.isDev) {
			return;
		}
		this.activeItem = item;
	}

	// TODO move to service
	onClickPreview(page: IPage): void {
		const preview = this.options.previewCallback(page);
		if (preview) {
			this.setBusy(true);
			this.progressService.onNextNotBusy(() => {
				this.setBusy(false);
				this.close();
			});
		}
	}

	// TODO Type
	onClickAdd(infoItem: ICatalogAddInfo): void {
		const item = infoItem.item;
		if (!item) {
			return;
		}

		const isDuplicate = infoItem.isDuplicate as boolean;
		if (this.isWidget) {
			const byRef = isDuplicate ? false : item.standardWidgetId ? true : false;
			this.addInternal(item, byRef, isDuplicate);
		} else {
			if (isDuplicate) {
				this.addInternal(item, false, isDuplicate);
			} else {
				this.addInternal(item, true, isDuplicate);
			}
		}
	}

	editPublishConfiguration(infoItem: any): void {
		if (infoItem.item) {
			this.setBusy(true);
			if (this.isWidget) {
				this.editPublishedWidgetConfiguration(infoItem.item);
			} else {
				this.editPublishedPageConfiguration(infoItem.item);
			}
		}
	}

	/**
	 * Removes a tag from filter.
	 */
	removeTag(tag: string): void {
		ArrayUtil.remove(this.filter.tags, tag);
		this.onFilterChange();
	}

	editPublishedPageConfiguration(item: any): void {
		const self = this;

		// Extend page to get content and widgetRefs
		this.pageService.getPublishedExtended(item.id).subscribe(
			(response) => {
				const extendedPage = response.content;

				// Let user make edits
				self.pageService
					.editPageConfiguration(
						extendedPage,
						true,
						self.containerService.dialogParent,
						true,
					)
					.subscribe((result) => {
						if (result) {
							// Update page in catalog
							const pageId = extendedPage.data.id;
							const filterExists =
								self.isFilterActive || self.filter.category !== null;
							self.loadStart(filterExists, pageId);

							// Update page in container
							if (self.containerService.getContainer().contains(pageId)) {
								self.containerService.refresh({});
							}
							self.pageService.showPublishedToast(
								this.pageService.getPageTitleLocalizedOrDefault(extendedPage),
							);
						} else {
							self.setBusy(false);
						}
					});
			},
			(r: IOperationResponse) => {
				self.pageService.handleError(r);
				self.setBusy(false);
			},
		);
	}

	showSaveUserFilter(): void {
		const dialog = this.dialogService
			.modal(CatalogSaveFilterComponent, this.containerService.dialogParent)
			.id("lm-sf-mdl")
			.title(this.lang.saveView)
			.afterClose((r: IDialogResult) => {
				if (r && r.value) {
					const userFilter: IUserFilter = {
						name: r.value,
						filter: CoreUtil.copy(this.filter),
					};
					const owner = this.filter.owner;
					if (owner && owner !== this.currentUser.id) {
						userFilter.ownerDisplayName = this.ownerSearchModel.value.name;
					}
					this.userFilters.push(userFilter);
					this.saveFiltersUserSetting();
				}
			});

		dialog
			.apply((component) => {
				component.modalDialog = dialog;
			})
			.open();
	}

	search(): void {
		// If in details, exiting for now
		if (this.activeItem) {
			this.activeItem = null;
		}
		this.filter.query = this.catalogSearchQuery;
		this.isSearchActive = true;
		this.onFilterChange(true);
	}

	clearSearch(event?: Event): void {
		if (event) {
			event.stopPropagation();
			event.preventDefault();
		}

		this.filter.query = null;
		this.catalogSearchQuery = null;
		if (this.isSearchActive) {
			this.isSearchActive = false;
			this.onFilterChange();
		}
	}

	removeFromAllArrays(id: string): void {
		const remove = ArrayUtil.removeByProperty;
		let name: string;
		if (this.isWidget) {
			name = "widgetId";
			remove(this.items, name, id);
			remove(this.featuredItems, name, id);
			remove(this.recentItems, name, id);
			this.saveRecentUserSetting();
			remove(this.newItems, name, id);
		} else {
			name = "id";
			remove(this.items, name, id);
			remove(this.featuredItems, name, id);
			remove(this.newItems, name, id);
		}
	}

	moreButtonVisible(items: ICatalogItem[]): boolean {
		if (items) {
			return items.length > 3;
		}
		return false;
	}

	getItemColor(item: ICatalogItem): string {
		if (item) {
			if (this.isWidget) {
				return this.catalogService.getWidgetCategoryColor(item.category);
			} else {
				return (
					UIUtil.numberToHexCode(item.data.color) || Constants.defaultColor
				);
			}
		}
	}

	getType(item: ICatalogItem): string {
		let label: string;
		if (this.isWidget) {
			const isPublished =
				item && !StringUtil.isNullOrWhitespace(item.standardWidgetId);
			if (isPublished) {
				label = this.lang.publishedWidgetTag;
			} else {
				label = this.lang.standardWidget;
			}
		}
		return label;
	}

	getCategoryName(category: number): string {
		return this.catalogService.getLocalizedCategoryName(category);
	}

	selectCategory(category: number): void {
		if (category && this.filter.category !== category) {
			this.filter.category = category;
			this.onFilterChange();
		}
	}

	setSessionFilter(): void {
		let filterData = { filter: this.filter } as any;
		if (this.ownerSearchModel) {
			filterData = Object.assign({}, filterData, {
				userModel: this.ownerSearchModel,
			});
		}
		if (this.selectedFilterName) {
			filterData = Object.assign({}, filterData, {
				userFilter: this.selectedFilterName,
			});
		}

		const stringValue = JSON.stringify(filterData);
		if (this.isWidget) {
			if (this.isBannerMode) {
				sessionStorage.setItem("lmHeroCatalogSavedSessionFilter", stringValue);
			} else {
				sessionStorage.setItem(
					"lmWidgetCatalogSavedSessionFilter",
					stringValue,
				);
			}
		} else {
			sessionStorage.setItem("lmPageCatalogSavedSessionFilter", stringValue);
		}
	}

	onClickUserFilter(event: any, userFilter: IUserFilter): void {
		// If in details, exiting for now
		if (this.activeItem) {
			this.activeItem = null;
		}
		const filter = CoreUtil.copy(userFilter.filter);
		if (filter.owner && typeof filter.owner !== "string") {
			this.ownerSearchModel.value.name = (filter.owner as ICatalogUser).name;
			filter.owner = (filter.owner as ICatalogUser).id;
		}

		const ownerDisplayName = userFilter.ownerDisplayName;
		if (ownerDisplayName) {
			this.ownerSearchModel = {
				value: { id: filter.owner, name: ownerDisplayName },
				inputText: ownerDisplayName,
			};
		}

		if (filter.query) {
			this.isSearchActive = true;
			this.catalogSearchQuery = filter.query;
		}

		this.filter = filter;
		this.onFilterChange();
		this.selectedFilterName = userFilter.name;
	}

	onClickDeleteUserFilter(event: any, filter: IUserFilter): void {
		const lang = this.lang;
		const buttons = [
			{
				text: lang.no,
				id: "lm-cat-deletefilter-message-no",
				click: (e, modal) => {
					modal.close(true);
				},
			},
			{
				text: lang.yes,
				isDefault: true,
				id: "lm-cat-deletefilter-message-yes",
				click: (e, modal) => {
					if (this.selectedFilterName === filter.name) {
						this.selectedFilterName = "";
					}
					ArrayUtil.remove(this.userFilters, filter);
					this.saveFiltersUserSetting();
					modal.close(true);
				},
			},
		];
		this.messageService
			.message()
			.title(lang.deleteSavedCatalogView)
			.message(
				lang.format(
					lang.confirmDeleteSavedCatalogView,
					HtmlUtil.escapeStringForHtml(filter.name),
				),
			)
			.beforeOpen(() => {
				event.stopPropagation();
				return true;
			})
			.buttons(buttons)
			.attributes({ name: "id", value: "lm-cat-deletefilter-message" })
			.open();
	}

	setOrderBy(item: IOrderBy): void {
		if (item && this.filter.orderBy !== item) {
			this.filter.orderBy = item;
			this.onFilterChange();
		}
	}

	onFilterChange(
		searchChange?: boolean,
		fromSessionFilter?: boolean,
		updatedItemId?: string,
	): void {
		if (this.isBusy()) {
			return;
		}
		this.setBusy(true);

		if (this.filter.type === CatalogContentType.Published) {
			this.filter.cloudSuite = null;
		}

		if (this.selectedFilterName && !fromSessionFilter) {
			this.selectedFilterName = "";
		}

		this.paging = null;
		if (
			!this.filter.category ||
			(this.filter.category === WidgetCategory.MyRecent && searchChange)
		) {
			this.filter.category = WidgetCategory.All;
		}

		if (this.filter.category === WidgetCategory.MyRecent && !this.isDev) {
			// My Recent, not fetched
			const items = this.recentItems;
			if (updatedItemId) {
				this.onClickDetails(this.getLoadedItem(updatedItemId, items));
			} else {
				this.activeItem = null;
			}
			this.items = items;
			this.setBusy(false);
		} else {
			this.loadItems(updatedItemId);
		}

		// Always scroll item list to top
		$("#lm-cat-list-cont").scrollTop(0);

		this.setIsFilterActive();
	}

	onClickSelectAddTag(tag: string): void {
		if (tag && tag.length >= 2) {
			this.addTag(tag);
			this.tagModel = "";
		}
	}

	addTag(tag: string): void {
		if (
			this.filter.category !== WidgetCategory.MyRecent &&
			!ArrayUtil.contains(this.filter.tags, tag) &&
			this.filter.tags.length < 5
		) {
			this.filter.tags.push(tag);
			this.onFilterChange();
		}
	}

	goToHome(): void {
		if (this.activeItem) {
			this.activeItem = null;
		}

		if (this.selectedFilterName) {
			this.selectedFilterName = "";
		}

		this.filter = {
			type: CatalogContentType.All,
			owner: null,
			category: null,
			orderBy: this.orderByArray[0],
			application: null,
			cloudSuite: null,
			tags: [],
		};

		if (!this.homeLoaded) {
			this.loadStart(false);
		}

		if (this.ownerSearchModel) {
			this.ownerSearchModel.inputText = "";
		}
	}

	close(): void {
		this.dialog.close(this.isWidgetUpdated);
	}

	setIsFilterActive() {
		const filter = this.filter;
		this.isFilterActive =
			filter.tags.length > 0 ||
			filter.application !== null ||
			filter.cloudSuite !== null ||
			filter.owner !== null ||
			filter.type !== CatalogContentType.All ||
			!StringUtil.isNullOrWhitespace(filter.query);
	}

	stringify(bool: boolean): string {
		return bool.toString();
	}

	isBusy(): boolean {
		return this.catalogService.isBusy();
	}

	private initView() {
		if (this.options.detailItem) {
			this.goToHome();
		} else {
			if (this.initializeFilter()) {
				this.loadStart(true);
			} else {
				this.goToHome();
			}
		}
	}

	private initWidgetMode(): void {
		const lang = this.lang;
		const options = this.options;
		this.catalogMode = "widget";
		this.isWidget = true;
		this.isBannerMode = options.isBanner;
		this.bannerWidgetCount = options.bannerWidgetCount;
		this.isDev = this.devService.isDev;
		this.title = this.isBannerMode
			? lang.bannerWidgetCatalog
			: lang.widgetCatalog;
		this.labelAdd = lang.addWidget;
		this.labelNoItems = lang.noWidgetsFound;
		this.labelFeatured = lang.featuredWidget;
	}

	private initPageMode(): void {
		const lang = this.lang;
		this.catalogMode = "page";
		this.title = lang.pageCatalog;
		this.labelAdd = lang.addPage;
		this.labelNoItems = lang.noPagesFound;
		this.labelFeatured = lang.featuredPage;
	}

	private initDialogEvents(): void {
		this.dialog.opened(() => {
			this.ngZone.run(() => (this.isOpened = true));
		});

		this.dialog.closed(() => {
			this.setSessionFilter();
			try {
				// Toolbar might not exist due to ngIf statement
				this.listToolbar.toolbar.destroy();
			} catch (ex) {}
		});
	}

	private loadFilters(): void {
		const settings = this.context.settings;
		const setting = this.isWidget
			? settings.getWidgetCatalogFilters()
			: settings.getPageCatalogFilters();
		const filters = CoreUtil.tryParse<IUserFilter[]>(setting);
		if (filters) {
			this.userFilters = filters;
		}
	}

	private setBusy(isBusy: boolean): void {
		this.catalogService.setBusy(isBusy);
	}

	private initializeFilter(): boolean {
		const lastSessionFilter = this.getSessionFilter();
		if (!lastSessionFilter) {
			return false;
		}

		const filter = lastSessionFilter.filter as ICatalogFilter;
		this.filter = filter;
		if (filter.owner) {
			if (
				lastSessionFilter.userModel &&
				filter.owner === lastSessionFilter.userModel.value.id
			) {
				this.ownerSearchModel = lastSessionFilter.userModel;
			}
		}

		if (lastSessionFilter.userFilter) {
			this.selectedFilterName = lastSessionFilter.userFilter;
		}

		if (!this.isWidget && !this.isFeatureStandardPagesEnabled) {
			filter.type = CatalogContentType.All;
		}

		if (filter.query) {
			this.catalogSearchQuery = filter.query;
			this.isSearchActive = true;
		}

		return true;
	}

	private initAutocomplete(): void {
		this.tagsAutocompleteSource = (query, done) => {
			this.commonDataService
				.searchTags(query)
				.subscribe((response: IStringListResponse) => {
					const items = response.content.map((tag) => ({
						label: tag,
						value: tag,
					}));
					done(query, items);
				});
		};
		this.autocompleteTemplate = Templates.autocompleteDefault;
	}

	private editPublishedWidgetConfiguration(info: IWidgetInfo): void {
		const self = this;
		const handle: IWidgetHandle = {
			id: info.widgetId,
			pid: info.standardWidgetId,
			byRef: true,
		};

		this.widgetService.getPublished(handle).subscribe(
			(publishedItem: IPublishedWidgetItem) => {
				const definition = publishedItem.definition;
				if (definition.custom) {
					definition.settings = WidgetUtil.applyRestrictions(
						definition.settings,
						definition.custom.metadata,
					);
				}

				// Extend widget with required data.
				const widget = info as IWidget;
				widget.instance = {};
				widget.definition = {};
				Object.assign(widget.definition, definition);
				widget.definition.lang = publishedItem.runtimeLocalization;
				widget.isCatalogTitle = () => publishedItem.definition.isCatalogTitle;
				widget.isPublished = () => true;
				const isBannerWidget = this.isBannerMode;
				// Default values depend on from where the widget is edited
				widget.isBanner = () => isBannerWidget;

				self.widgetService
					.showPublishConfiguration(
						self.containerService.dialogParent,
						widget,
						publishedItem,
						null,
						true,
					)
					.subscribe(
						(result) => {
							if (result) {
								const publishDefinition = result.value.publishedItem
									.definition as IWidgetDefinition;
								const filterExists =
									self.isFilterActive || self.filter.category !== null;
								self.loadStart(filterExists, info.widgetId);
								if (this.editModeService.isLayout()) {
									// Cannot refresh directly in layout edit mode since it breaks the container
									this.delayLayoutModeRefresh();
								} else {
									self.containerService.refresh({});
								}

								self.widgetService.showPublishedToast(
									publishDefinition.custom.title,
								);
								self.isWidgetUpdated = true;
								if (this.options.republishCallback) {
									this.options.republishCallback(publishDefinition);
								}
							} else {
								self.setBusy(false);
							}
						},
						(response: IOperationResponse) => {
							self.widgetService.handleError(response);
							this.setBusy(false);
						},
					);
			},
			(response: IOperationResponse) => {
				self.widgetService.handleError(response);
				this.setBusy(false);
			},
		);
	}

	private delayLayoutModeRefresh(): void {
		const unsubscribe = this.editModeService
			.stopped()
			.on((editMode: IEditMode) => {
				if (editMode.mode === EditModes.layout) {
					if (editMode.isSave) {
						this.containerService.getContainer().refreshOnNextSave();
					} else {
						this.containerService.refresh({});
					}
					unsubscribe();
				}
			});
	}

	private isLoadError(response: ICatalogStartResponse): boolean {
		return HttpUtil.isError(NumUtil.getInt(response.errorHttpCode, 0));
	}

	private loadStart(
		sessionFilterExists: boolean,
		updatedItemId?: string,
	): void {
		if (this.isDev) {
			const devWidgets = this.getDevWidgets();
			this.newItems = devWidgets;
			this.items = devWidgets;
			return;
		}

		this.setBusy(true);
		const self = this;
		this.options.startProvider(this.isBannerMode).subscribe(
			(response: ICatalogStartResponse) => {
				self.onLoadStartCompleted(response, sessionFilterExists, updatedItemId);
			},
			(response: ICatalogStartResponse) => {
				this.logError("Failed to load catalog " + response.toErrorLog());
				// Part of the data might be loaded OK try to load as mutch as possible
				self.onLoadStartCompleted(response, sessionFilterExists);

				if (this.isLoadError(response)) {
					this.showLoadError();
					return;
				}

				// Could be any kind of response but might be a response with a message
				// For pages it does not matter if the featured pages call failed
				if (self.isWidget) {
					// Only the application list is critical to the filtering
					// The other sections might be empty if there is an error
					if (!self.applications) {
						self.showLoadError();
					}
				}

				if (this.hasServerCancelMessage(response)) {
					this.showLoadWarning();
				}
			},
		);
	}

	private onLoadStartCompleted(
		response: ICatalogStartResponse,
		sessionFilterExists: boolean,
		updatedItemId?: string,
	): void {
		if (response) {
			const maxFeatured = response.maxFeatured;
			this.maxFeatured = maxFeatured;

			const featuredItems = this.isWidget
				? response.featuredWidgets
				: response.featuredPages;
			if (featuredItems && featuredItems.length > maxFeatured) {
				this.trimFeaturedItems(featuredItems, maxFeatured);
			}

			this.initDetailItem(featuredItems);

			this.featuredItems = this.addAdditionalInfo(featuredItems, true);
			this.newItems = this.addAdditionalInfo(
				this.isWidget ? response.updatedWidgets : response.updatedPages,
			);
			this.recentItems = response.myRecentWidgets
				? this.addAdditionalInfo(response.myRecentWidgets)
				: [];
			this.tags = response.tags || [];
			this.homeLoaded = true;

			this.initApplications(response.applications);
			this.initCloudSuites(response.cloudSuites);
		}

		if (sessionFilterExists) {
			this.setBusy(false);
			this.onFilterChange(false, true, updatedItemId);
		} else if (updatedItemId) {
			// Reload the edited item's detail view
			const allItems = this.newItems.concat(
				this.recentItems,
				this.featuredItems,
			);
			this.onClickDetails(this.getLoadedItem(updatedItemId, allItems));
			this.setBusy(false);
		} else {
			this.setBusy(false);
		}
	}

	private initApplications(applications: IApplicationInfo[]): void {
		if (applications) {
			this.applications = applications.filter(
				(item, index, array) =>
					ArrayUtil.indexByProperty(
						array,
						"logicalIdPrefix",
						item.logicalIdPrefix,
					) === index,
			);

			const applicationFilter = this.filter.application;
			if (applicationFilter) {
				this.filter.application =
					this.applications.find(
						(app) => app.logicalIdPrefix === applicationFilter.logicalIdPrefix,
					) || applicationFilter;
			}
		} else {
			this.applications = [];
		}
	}

	private initCloudSuites(cloudSuites: ICloudSuiteInfo[]): void {
		if (cloudSuites) {
			this.cloudSuites = cloudSuites.filter(
				(item, index, array) =>
					ArrayUtil.indexByProperty(array, "key", item.key) === index,
			);

			const cloudSuiteFilter = this.filter.cloudSuite;
			if (cloudSuiteFilter) {
				this.filter.cloudSuite =
					this.cloudSuites.find(
						(suite) => suite.key === cloudSuiteFilter.key,
					) || cloudSuiteFilter;
			}
		} else {
			this.cloudSuites = [];
		}
	}

	private trimFeaturedItems(items: ICatalogItem[], limit: number): void {
		// Trim featured items if they exceed the featured limit
		items.splice(limit - 1, items.length - limit);
	}

	private addInternal(
		item: ICatalogItem,
		byRef: boolean,
		isDuplicate?: boolean,
	): void {
		const self = this;
		self.catalogService.setBusy(true);
		const busyCallback = (successful: boolean) => {
			// Only add to recent if successful adding
			if (successful) {
				if (self.isWidget) {
					self.addToRecent(item);

					if (self.isBannerMode) {
						self.bannerWidgetCount++;

						if (self.bannerWidgetCount === Constants.bannerWidgetCountMax) {
							self.close();
						}
					}
				}
			}
			self.catalogService.setBusy(false);
		};
		const addCatalog: ICatalogAddItem = {
			item: item,
			byRef: byRef,
			busyCallback: busyCallback,
			isDuplicate: isDuplicate,
		};
		this.options.addCallback(addCatalog);
	}

	private addToRecent(widget): void {
		ArrayUtil.removeByProperty(this.recentItems, "widgetId", widget.widgetId);
		const length = this.recentItems.unshift(widget);
		if (length > 10) {
			this.recentItems.pop();
		}

		if (!this.isDev) {
			this.saveRecentUserSetting();
		}

		UIUtil.refreshSvgIcons($("#lm-cat-list-div"));
	}

	private saveRecentUserSetting(): void {
		const context = this.context;
		const recentItemsString = this.recentItems
			.map((item) => {
				const standardId = item.standardWidgetId;
				const id = item.widgetId;
				return standardId ? id + ":" + standardId : id;
			})
			.join(",");
		if (this.isBannerMode) {
			context.settings.setRecentHeroWidgets(recentItemsString);
		} else {
			context.settings.setRecentWidgets(recentItemsString);
		}
		this.recentItemsString = recentItemsString;
		context.settings.saveUserSettings();
	}

	private saveFiltersUserSetting(): void {
		if (this.isWidget) {
			this.context.settings.setWidgetCatalogFilters(
				JSON.stringify(this.userFilters),
			);
		} else {
			this.context.settings.setPageCatalogFilters(
				JSON.stringify(this.userFilters),
			);
		}

		this.context.settings.saveUserSettings();
	}

	private addAdditionalInfo(
		items: ICatalogItem[],
		isFeatured?: boolean,
	): ICatalogItem[] {
		if (items && items.length > 0) {
			if (this.isWidget) {
				for (const widget of items) {
					this.extendWidget(widget, isFeatured);
				}
			} else {
				for (const page of items) {
					this.extendPage(page, isFeatured);
				}
			}
		} else {
			items = [];
		}
		return items;
	}

	private extendWidget(widget: ICatalogItem, isFeatured?: boolean) {
		widget.displayIcon = this.widgetService.createImagePath(
			widget as IWidgetInfo,
		);
		if (isFeatured) {
			widget.featuredClass = this.widgetService.getFeaturedBackgroundClass(
				widget.category,
			);
		}
	}

	private extendPage(page: ICatalogItem, isFeatured?: boolean) {
		if (!page.data) {
			page.data = {};
		}
		page.id = page.data.id;
		page.tags = page.data.tags;
		page.title = page.title || page.data.title;
		page.description = page.description || page.data.description;
		if (isFeatured) {
			page.featuredClass = this.pageService.getFeaturedBackgroundClass(
				page.data.color,
			);
		}
	}

	private showLoadError(): void {
		const lang = this.lang;
		this.showError(lang.unableToLoad, lang.errorGeneric);
	}

	private showLoadWarning(): void {
		const lang = this.lang;
		this.showError(lang.catalogRequestCancelled, lang.catalogTimeout);
	}

	private loadItems(updatedItemId?: string): void {
		if (this.isDev) {
			return;
		}
		this.setBusy(true);

		const request = this.createRequest(
			this.filter.category === WidgetCategory.NewUpdated,
		);
		request.pageSize = 15;

		if (updatedItemId) {
			// Reset paging and items since a page/widget has been updated
			request.paging = null;
			this.items = [];
		}

		const paging = this.paging; // Capture current value for potential async issues

		this.options.provider(request).subscribe(
			(response: ICatalogResponse) => {
				const items = response.content;
				if (items) {
					if (paging) {
						this.items = this.items.concat(this.addAdditionalInfo(items));
						this.updateRelatedTags(items, false);
					} else {
						this.items = this.addAdditionalInfo(items);
						this.updateRelatedTags(items, true);
					}
				}
				this.paging = response.paging;
				this.hasMore =
					(request.includeStandard && !this.paging.standardEnd) ||
					(request.includePublished && !this.paging.publishedEnd);

				if (updatedItemId) {
					// Reload the edited item's detail view, updated items will always be in new items array
					this.onClickDetails(this.getLoadedItem(updatedItemId, this.newItems));
				} else {
					this.activeItem = null;
				}

				if (this.hasServerCancelMessage(response)) {
					this.showLoadWarning();
				}

				this.setBusy(false);
			},
			(response: IOperationResponse) => {
				this.logError(response.toErrorLog());
				if (!this.paging) {
					this.items = [];
				}

				this.setBusy(false);
				if (this.hasServerCancelMessage(response)) {
					this.showLoadWarning();
				} else {
					this.showLoadError();
				}
			},
		);
	}

	private hasServerCancelMessage(response: ICatalogResponse): boolean {
		if (response.errorList) {
			for (const error of response.errorList) {
				if (
					error.code === ResponseErrorCodes.requestTimeout ||
					error.code === ResponseErrorCodes.requestLoopTimeout
				) {
					return true;
				}
			}
		}
		return false;
	}

	private createRequest(isNewUpdated?: boolean): ICatalogRequest {
		const request: IWidgetCatalogRequest = {
			sortOrder: isNewUpdated
				? SortOrder.Descending
				: this.filter.orderBy.order,
			sortBy: isNewUpdated
				? EntitySortBy.ChangeDate
				: this.filter.orderBy.entity,
			paging: this.paging,
			includePublished:
				this.filter.type === CatalogContentType.All ||
				this.filter.type === CatalogContentType.Published,
			includeStandard:
				this.filter.type === CatalogContentType.All ||
				this.filter.type === CatalogContentType.Standard,
			logicalId: this.filter.application
				? this.filter.application.logicalIdPrefix
				: null,
			cloudSuite: this.filter.cloudSuite ? this.filter.cloudSuite.key : null,
			query: this.getQuery(),
			tags: this.filter.tags.map((tag: string) => {
				return `${tag}`;
			}),
		};

		if (this.filter.owner) {
			request.ownerId = this.filter.owner;
		}

		if (this.isWidget) {
			const widgetRequest = request as IWidgetCatalogRequest;
			// Include normal widgets by default or there will be no results
			const isBanner = this.isBannerMode;
			widgetRequest.includeNormal = !isBanner;
			widgetRequest.includeBanner = isBanner;

			const isMobileWidgetsEnabled =
				this.context.settings.isMobileWidgetsEnabled();
			// Only include mobile widgets if you are an administrator
			widgetRequest.includeMobile = isMobileWidgetsEnabled && this.isPageAdmin;

			widgetRequest.category =
				this.filter.category > 0 ? this.filter.category : 0;
		}

		return request;
	}

	private updateRelatedTags(items: ICatalogItem[], newSearch = false) {
		if (newSearch) {
			this.relatedTags = [];
		}
		let tags: string[];
		items.forEach((item) => {
			const tagString = this.isWidget ? item.tags : item.data.tags;
			if (tagString) {
				tags = tagString.split("#");
				tags.forEach((tag) => {
					if (
						tag &&
						!ArrayUtil.contains(this.relatedTags, tag) &&
						!ArrayUtil.contains(this.filter.tags, tag)
					) {
						this.relatedTags.push(tag);
					}
				});
				// Force change detection.
				this.relatedTags = this.relatedTags.slice();
			}
		});
	}

	private getQuery(): string {
		const query = (this.filter.query || "").trim();
		return query ? query : null;
	}

	private getSessionFilter(): ICatalogSessionFilter {
		const filterString = sessionStorage.getItem(this.getFilterKey());
		const sessionFilter =
			CoreUtil.tryParse<ICatalogSessionFilter>(filterString);
		const hasFilter =
			sessionFilter && sessionFilter.filter && sessionFilter.filter.category;
		if (!hasFilter) {
			return null;
		}

		const filter = sessionFilter.filter;
		if (filter.orderBy) {
			// Don't rely on the stored name which may change when the language is changed
			filter.orderBy = this.getOrderBy(filter.orderBy);
		}

		return sessionFilter;
	}

	private getOrderBy(orderBy: IOrderBy): IOrderBy {
		return ArrayUtil.find(this.orderByArray, (item) => {
			return item.entity === orderBy.entity && item.order === orderBy.order;
		});
	}

	private getFilterKey() {
		if (this.isWidget) {
			return this.isBannerMode
				? "lmHeroCatalogSavedSessionFilter"
				: "lmWidgetCatalogSavedSessionFilter";
		}
		return "lmPageCatalogSavedSessionFilter";
	}

	private getDevWidgets(): ICatalogItem[] {
		const items = this.devService.getWidgetItems();
		const infos: IWidgetInfo[] = [];

		for (const item of items) {
			const definition = item.widgetDefinition;
			const localization = definition.localization;
			const id = definition.widgetId;
			const categoryInt = WidgetCategory.getCategory(definition.category);
			const info: IWidgetInfo = {
				widgetId: id,
				standardWidgetId: definition.standardWidgetId,
				title: localization
					? localization[WidgetConstants.widgetTitle]
					: definition.title,
				description: localization
					? localization[WidgetConstants.widgetDescription]
					: definition.description,
				category: categoryInt,
				owner: definition.owner,
				version: definition.version,
				iconFile: definition.iconFile,
			};
			infos.push(info);
		}

		return this.addAdditionalInfo(infos);
	}

	private getLoadedItem(id: string, items: ICatalogItem[]): ICatalogItem {
		let item: ICatalogItem;
		if (this.isWidget) {
			item = ArrayUtil.itemByProperty(items, "widgetId", id);
		} else {
			item = ArrayUtil.itemByProperty(items, "id", id);
		}
		return item;
	}

	private initDetailItem(featured: ICatalogItem[]) {
		const detailItem = this.options.detailItem;
		if (detailItem) {
			const itemCopy = { ...detailItem };
			const isFeatured =
				featured &&
				featured.length &&
				featured.some((item) => item.data.id === itemCopy.data.id);
			this.extendPage(itemCopy, isFeatured);
			this.onClickDetails(itemCopy);
		}
	}
}
