import { Component, OnInit } from "@angular/core";
import { SohoModalDialogRef } from "ids-enterprise-ng";
import { DialogService, StringUtil } from "lime";
import {
	DataService,
	IBadgePopoverInfo,
	IWidget,
	IWidgetDefinition,
	IWidgetDetailInfoResponse,
	LanguageService,
	WidgetService,
	WidgetUtil,
} from "lime/core";

/**
 * About widget component.
 */
@Component({
	templateUrl: "./widget-about.html",
})
export class WidgetAboutComponent implements OnInit {
	badges: IBadgePopoverInfo[];
	brokenMessage: string;
	deprecationInfo: string;
	dialog: SohoModalDialogRef<WidgetAboutComponent>;
	displayVersion: string;
	helpUrl: string;
	isBroken = false;
	lang: ILanguageLime;
	name: string;
	ownerName: string;
	title: string;
	titleBasedOn: string;
	version: string;
	widget: IWidget;
	widgetId: string;

	private definition: IWidgetDefinition;

	constructor(
		private readonly dialogService: DialogService,
		private readonly dataService: DataService,
		private readonly widgetService: WidgetService,
		languageService: LanguageService,
	) {
		this.lang = languageService.getLanguage();
	}

	ngOnInit() {
		this.widgetId = this.widget.data.id;

		if (this.checkBroken()) {
			return;
		}

		this.initDefinition();
		this.initOwner();
		this.initDeprecated();
		this.initHelp();
	}

	close(): void {
		this.dialog.close();
	}

	copyToClipboard(): void {
		const definition = this.definition;
		const basedOn = this.titleBasedOn
			? `\nBased on: ${this.titleBasedOn},`
			: "";
		const basedOnId = definition.standardWidgetId
			? `\nBased on (ID): ${definition.standardWidgetId},`
			: "";
		const ownerName = definition.ownerName
			? `, \nOwner Name: ${definition.ownerName}`
			: "";
		const ownerId = definition.owner ? `, \nOwner ID: ${definition.owner}` : "";
		const widgetVersion =
			this.version !== this.displayVersion
				? `\nWidget version: ${this.version}`
				: "";
		const version = `\nVersion: ${this.displayVersion}${widgetVersion}`;

		const copyString = `ID: ${this.widgetId}, \nTitle: ${this.widget.title}, \nName: ${this.name},${basedOn}${basedOnId}${version}${ownerName}${ownerId}`;
		this.dialogService.copyToClipboard({ copyData: copyString });
	}

	private initDefinition(): void {
		const widget = this.widget;
		const definition = this.widgetService.getCachedDefinition(widget.id);
		this.definition = definition;
		this.badges = WidgetUtil.getBadges(definition, this.lang);

		// Set the current title
		this.title = widget.title;

		// Set the widget catalog title
		this.name = definition.title;

		const versionInfo = this.widgetService.getWidgetVersionInfo(definition);
		if (versionInfo) {
			this.version = versionInfo.version;
			this.displayVersion = versionInfo.displayVersion || versionInfo.version;
		} else {
			this.version = definition.version;
			this.displayVersion = definition.displayVersion || definition.version;
		}

		if (definition.isPublished && !widget.isDev) {
			// Set the standard widget title for a published widget
			this.titleBasedOn = definition.standardTitle;
		}
	}

	private initOwner(): void {
		const ownerName = this.definition.ownerName;
		if (ownerName) {
			this.ownerName = ownerName;
		} else if (this.definition.isPublished) {
			// Load owner name if missing for published widgets
			this.loadOwner();
		}
	}

	private initDeprecated(): void {
		const definition = this.definition;
		if (definition.isDeprecated) {
			const info = definition.deprecatedInfo;
			if (info && !StringUtil.isNullOrWhitespace(info)) {
				this.deprecationInfo = info;
			} else {
				this.deprecationInfo = definition.isPublished
					? this.lang.get("deprecatedParentWidget")
					: this.lang.get("deprecatedWidget");
			}
		}
	}

	private initHelp(): void {
		let helpUrl = this.definition.helpUrl;
		this.helpUrl = helpUrl;
		if (helpUrl && helpUrl.indexOf("{") >= 0) {
			helpUrl = this.widget.context.resolveAndReplace(helpUrl);

			const context = this.widget.context;
			const observable = context.resolveAndReplaceAsync(helpUrl, null);
			observable.subscribe((resolved: string) => {
				this.helpUrl = resolved;
			});
		}
	}

	private checkBroken(): boolean {
		if (this.widget.isBroken()) {
			this.brokenMessage = WidgetUtil.getBrokenReason(
				this.lang,
				this.widget.data.brokenReason,
			);
			this.isBroken = true;
			return true;
		}
		return false;
	}

	private loadOwner(): void {
		const definition = this.definition;
		const widgetHandle = {
			id: definition.widgetId,
			pid: definition.standardWidgetId,
		};

		const self = this;
		this.dataService
			.post("/widget/catalog/detail", { content: widgetHandle })
			.subscribe((r: IWidgetDetailInfoResponse) => {
				try {
					const ownerName = r.content.widgetDefinitionItem.definition.ownerName;
					self.ownerName = ownerName;
					self.definition.ownerName = ownerName;
				} catch (e) {
					// No op
				}
			});
	}
}
