import { Component, OnInit, ViewChild, ViewContainerRef } from "@angular/core";
import {
	SohoColorPickerComponent,
	SohoModalDialogRef,
} from "ids-enterprise-ng";
import { DialogButtonType } from "lime";
import {
	AccessType,
	Constants,
	ContextService,
	IContext,
	IOperationResponse,
	IPage,
	IPageContent,
	IPageData,
	IPageDataDialogValue,
	IPageDataResponse,
	LanguageService,
	ModalDialogBase,
	PageDataValidator,
	PageService,
	PageUtil,
	UIUtil,
} from "lime/core";

/**
 * Controller class for the page settings dialog.
 */
@Component({
	templateUrl: "./page-settings.html",
})
export class PageSettingsComponent extends ModalDialogBase implements OnInit {
	@ViewChild(SohoColorPickerComponent, { static: false })
	colorpicker: SohoColorPickerComponent;
	@ViewChild("textAreaRef", { read: ViewContainerRef, static: false })
	textAreaRef: ViewContainerRef;

	modalDialog: SohoModalDialogRef<PageSettingsComponent>;
	parameter: IPage;
	pageTitleLength;
	pageDescriptionLength;
	lang = {} as ILanguageLime;
	page = {} as IPage;
	data = {} as IPageData;
	isPublic: boolean;
	pageColor = Constants.defaultColor;
	colorpickerOptions = UIUtil.getPageColorPickerOptions();
	// If false, the component will not make a request to save the data when closed.
	saveDataOnClose: boolean;

	private readonly context: IContext;
	private editLevels = [];

	constructor(
		languageService: LanguageService,
		private readonly pageService: PageService,
		private readonly contextService: ContextService,
	) {
		super("PageSettingsComponent");

		this.context = contextService.getContext();
		this.lang = languageService.getLanguage();
		this.pageTitleLength = Constants.pageTitleLength;
		this.pageDescriptionLength = Constants.pageDescriptionLength;
	}

	ngOnInit() {
		const parameter = this.parameter;
		const page: IPage = {
			data: PageUtil.copy(parameter.data),
			isEditable: parameter.isEditable,
			isMandatory: parameter.isMandatory,
		};

		this.isPublic = page.data.viewAccess !== AccessType.Owner;

		this.data = page.data;
		this.page = page;

		this.pageColor = UIUtil.numberToHexCode(this.data.color);

		setTimeout(() => {
			$(this.textAreaRef.element.nativeElement).trigger("keyup.textarea");
		}, 0);

		this.initModalDialog();
	}

	save() {
		const page = this.page;
		page.data.color = UIUtil.hexCodeToNumber(this.colorpicker.getHexValue());
		const pageData = PageUtil.copy(page.data);
		const originalPage = this.parameter;
		const originalData = originalPage ? originalPage.data : null;
		let colorChanged = false;
		let returnValue: IPageDataDialogValue;

		const isValid = new PageDataValidator().validate(pageData);
		if (!isValid) {
			this.setCanClose(false);
			return;
		}

		if (this.saveDataOnClose) {
			this.setBusy(true);
			this.setCanClose(false);
			pageData.content = null as IPageContent; // Needed so widgets aren't overwritten on server
			const self = this;

			this.pageService.updateSettings(pageData).subscribe(
				(r: IPageDataResponse) => {
					// Return with the new values set to the page
					const returnPage = r.content;

					if (returnPage) {
						colorChanged = returnPage.color !== originalData.color;
						// Update real page with the new values
						PageUtil.copyValues(r.content, originalData);
					}

					self.setCanClose(true);
					self.setBusy(false);
					returnValue = {
						colorChanged: colorChanged,
					};
					self.closeWithResult(DialogButtonType.Ok, returnValue);
				},
				(r: IOperationResponse) => {
					self.setCanClose(true);
					self.setBusy(false);
					self.pageService.handleError(r);
				},
			);
		} else {
			this.setCanClose(true);
			colorChanged = page.data.color !== originalData.color;
			returnValue = {
				pageData: pageData,
				colorChanged: colorChanged,
			};
			this.closeWithResult(DialogButtonType.Ok, returnValue);
		}
	}
}
