import {
	ChangeDetectionStrategy,
	Component,
	Input,
	OnInit,
} from "@angular/core";
import { IEditableWidget, LanguageService } from "lime/core";

@Component({
	selector: "lm-page-edit-details",
	templateUrl: "page-edit-details.html",
	styleUrls: ["page-edit-details.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PageEditDetailsComponent implements OnInit {
	@Input() widget: IEditableWidget;

	lang: ILanguageLime;
	isBannerOnly: boolean;
	bannerInfoIcon: string;
	bannerInfoText: string;
	autoId: string;

	constructor(private readonly languageService: LanguageService) {
		this.lang = this.languageService.getLanguage();
	}

	ngOnInit(): void {
		const widget = this.widget;
		this.isBannerOnly =
			widget.isBannerEnabled && widget.containerChangeInfo.isAllowed === false;
		this.bannerInfoIcon = widget.isBannerEnabled ? "confirm" : "cancel";
		const lang = this.lang;
		this.bannerInfoText = widget.isBannerEnabled
			? this.isBannerOnly
				? lang.bannerEnabledYesOnly
				: lang.yes
			: lang.no;
		this.autoId =
			"lm-pedt-widget-row" +
			this.widget.layout.row +
			"-column" +
			this.widget.layout.column;
	}

	inBannerContainer(): boolean {
		const widget = this.widget;
		return (
			widget.containerChangeInfo.isBanner ||
			(widget.isBanner && widget.containerChangeInfo.isBanner !== false)
		);
	}
}
