import {
	ChangeDetectionStrategy,
	ChangeDetectorRef,
	Component,
	EventEmitter,
	HostListener,
	Input,
	OnDestroy,
	OnInit,
	Output,
} from "@angular/core";
import { LanguageService } from "lime/core";
import { Subscription, timer } from "rxjs";

export interface IFeaturedItem {
	title?: string;
	description?: string;
	data?: { title?: string; description?: string };
	featuredClass?: string;
}
@Component({
	selector: "lm-catalog-featured-component",
	templateUrl: "./catalog-featured.html",
	styleUrls: ["./catalog-featured.scss"],
	changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CatalogFeaturedComponent implements OnInit, OnDestroy {
	get headerTitle(): string {
		return this.isWidget ? this.lang.featuredWidget : this.lang.featuredPage;
	}

	get addLabel(): string {
		return this.isWidget ? this.lang.addWidget : this.lang.addPage;
	}
	@Input("items") featuredItems: IFeaturedItem[];
	@Input() limit: number;
	@Input() isWidget: boolean;
	@Input() canAdd: boolean;

	@Output() onClickAdd = new EventEmitter<any>();
	@Output() onClickDetails = new EventEmitter<any>();

	lang: ILanguageLime;
	visibleFeatured: IFeaturedItem;
	selectedIndex = 0;

	private subscription: Subscription;

	constructor(
		languageService: LanguageService,
		private readonly changeDetectorRef: ChangeDetectorRef,
	) {
		this.lang = languageService.getLanguage();
	}

	ngOnInit(): void {
		this.setFeatured(0);
		this.startInterval();
	}

	ngOnDestroy(): void {
		this.stopInterval();
	}

	@HostListener("mouseenter") onMouseEnter(): void {
		this.stopInterval();
	}

	@HostListener("mouseleave") onMouseLeave(): void {
		this.startInterval();
	}

	getDescription(featured: IFeaturedItem): string {
		return this.isWidget
			? featured.description
			: featured.description || featured.data.description;
	}

	getTitle(featured: IFeaturedItem): string {
		return this.isWidget
			? featured.title
			: featured.title || featured.data.title;
	}

	setFeatured(index: number): void {
		const featuredItems = this.featuredItems;
		if (featuredItems && featuredItems[index] && index < this.limit) {
			this.selectedIndex = index;
			this.visibleFeatured = featuredItems[index];
			this.changeDetectorRef.markForCheck();
		}
	}

	private startInterval(): void {
		const featuredItems = this.featuredItems;
		if (!featuredItems || featuredItems.length === 1) {
			return;
		}
		this.stopInterval();

		const observable = timer(5000, 5000);
		this.subscription = observable.subscribe(() => {
			const index =
				this.selectedIndex < featuredItems.length - 1
					? this.selectedIndex + 1
					: 0;
			this.setFeatured(index);
		});
	}

	private stopInterval(): void {
		if (this.subscription) {
			this.subscription.unsubscribe();
		}
	}
}
